UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('face-menace', 'Cet exercice avancé vise à aider votre chien à développer de la résilience émotionnelle face à des stimuli perçus comme menaçants. L''objectif est qu''il apprenne à rester calme et à réagir de manière appropriée, distinguant ainsi une véritable alerte d''une fausse alerte. En pratiquant régulièrement, votre chien gagnera en confiance et en autonomie face à des situations qui pourraient autrement le stresser.', 'Un exercice essentiel pour un chien qui ne panique plus face à la menace !', 'Apprenez à votre chien à évaluer et à réagir calmement face à des situations qu''il perçoit comme des menaces.', 'Face à la menace', 'Apprendre à votre chien à gérer ses émotions face à une situation perçue comme menaçante, en restant calme et en ayant une réaction adaptée. Il saura mieux faire la différence entre une vraie alerte et une fausse alerte.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien regarde le stimulus sans paniquer, reste à votre côté, et accepte volontiers une friandise ou une interaction lorsque le stimulus est présent.', 'Le chien présente des signes de stress excessif incontrôlable (tremblements, salivation importante, fuite, agressivité réactive).', '3 succès consécutifs sur 5 essais, où le chien reste calme et réceptif malgré la présence du stimulus.', 'Soyez attentif à tout signe de stress, de peur ou d''agressivité chez votre chien. Votre rôle est de le rassurer et de le guider, pas de le confronter avec force.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/face-menace.png'),
('fais-le-beau', 'Le ''Fais le beau'' est un excellent exercice pour renforcer la connexion avec votre chien et améliorer son autocontrôle. Il consiste à apprendre au chien à se tenir sur ses pattes arrière, tel un ours. Cet exercice nécessite patience et renforcement positif pour un apprentissage réussi.', 'Apprenez à votre chien à faire le beau, une posture impressionnante et amusante !', 'Guidez votre chien pour qu''il s''assoie sur ses pattes arrière, les pattes avant levées.', 'Fais le beau', 'Votre chien apprend à s''asseoir fièrement sur ses pattes arrière, comme un petit kangourou. Cet exercice améliore son équilibre et lui donne confiance en lui.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien se dresse sur ses pattes arrière et maintient la position pendant au moins 5 secondes sur commande verbale, avec une légère aide de leurre initial et sans perdre l''équilibre. Le chien semble serein et confiant pendant l''exercice.', 'Le chien montre des signes de fatigue, de détresse, de frustration ou de peur. S''il refuse systématiquement de tenter le mouvement ou s''il y a un risque de chute ou de blessure.', 'Après plusieurs séances de pratique (au moins 5), le chien devrait être capable de se tenir sur ses pattes arrière pendant au moins 3 secondes sur commande verbale, avec une aide minimale de leurre. L''exercice se termine par une récompense et des félicitations.', 'Soyez attentif à tout signe de gêne ou de douleur au niveau du dos ou des hanches de votre chien, car l''exercice peut être exigeant pour ces articulations. Vérifiez qu''il n''y a pas de glissades. Assurez-vous aussi que c''est un moment de plaisir partagé et non de contrainte.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/fais-le-beau.png'),
('fais-le-mort', 'Le ''Fais le mort'' est un excellent tour pour votre chien qui demande de la patience et de la répétition. Il enseigne au chien à rester immobile dans une position couchée prolongée. Cet exercice renforce la confiance et la communication entre vous et votre chien.', 'Apprenez à votre chien un tour amusant : faire le mort !', 'Apprenez à votre chien à se coucher sur le côté avec la commande "Fais le mort" !', 'Fais le mort', 'Le but est que votre chien se couche sur le côté et reste immobile, comme s''il faisait semblant de dormir ou d''être couché. C''est un tour rigolo et divertissant.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien se couche sur le flanc immédiatement sur commande verbale et/ou visuelle, et maintient la position pendant au moins 30 secondes, jusqu''à ce qu''un signal de fin soit donné.', 'Le chien montre des signes de stress, de fatigue excessive, ou une réticence marquée à l''exercice. Arrêter si le chien est blessé ou a mal.', 'Répéter l''exercice dans des contextes variés avec et sans distractions légères. Observer la réactivité et la durée de maintien de la position. Observer si le chien anticipe le signal de fin.', 'Restez très attentif aux signaux de votre chien. Le bâillement, les léchages de babines, les yeux fuyants, ou une posture raide sont des signes qu''il n''est pas à l''aise ou qu''il est fatigué. Adaptez-vous à son humeur.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/fais-le-mort.png'),
('fermer-tiroir', 'Cet exercice enseigne à votre chien à pousser un tiroir fermé avec son nez ou sa patte pour le refermer. C''est une astuce amusante et utile qui peut être appliquée à divers objets du quotidien. Il renforce la communication et la confiance entre vous et votre compagnon.', NULL, NULL, 'Fermer un tiroir', 'Pousser un tiroir avec le nez', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien ferme le tiroir de manière consistante et rapide dès la réception de la commande vocale, sans hésitation.', 'Le chien montre des signes de stress, de frustration, d''ennui ou de fatigue. Arrêtez la séance et reprenez plus tard avec une approche plus positive ou plus courte.', 'Après plusieurs séances, le chien devrait être capable de fermer le tiroir de manière autonome sur commande verbale ''Ferme'' dans divers environnements familiers.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/fermer-tiroir.png'),
('fetch', 'Le jeu du ''ramener'' est un excellent moyen de stimuler physiquement et mentalement votre chien tout en renforçant votre lien. Il enseigne à votre chien à aller chercher un objet, à le ramener vers vous, et à le lâcher. C''est un exercice polyvalent adaptable à différents environnements et objets.', NULL, NULL, 'Fetch (ramener)', 'Ramener le troupeau vers le berger', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien ramène l''objet au moins 4 fois sur 5 lancers dans un environnement contrôlé, et le lâche par échange ou sur commande.', 'Le chien montre des signes de fatigue excessive (halètement important, ralentissement), d''ennui (se couche, ignore les appels), ou de frustration (agressivité envers l''objet ou le maître).', 'Observer si le chien recherche activement l''objet, le ramène vers le maître sans hésitation et le lâche sur commande.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/fetch.png'),
('flanking', 'Le flanking est un mouvement latéral qui enseigne au chien à se déplacer à vos côtés, que ce soit à droite ou à gauche. Cet exercice améliore la connexion et la réactivité du chien, tout en renforçant le contrôle dans différentes positions. Il est utile pour la fluidité des transitions de race et pour des disciplines comme l''agility ou le heelwork.', NULL, NULL, 'Flanking (mouvement latéral)', 'Déplacer le troupeau latéralement', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient une position latérale précise à la hanche du handler sur plusieurs pas, sans se laisser distraire et en répondant positivement aux encouragements. Le mouvement est fluide et synchronisé.', 'Le chien montre des signes de stress, de fatigue, de frustration ou de peur. Le handler ne parvient pas à maintenir une communication claire ou l''exercice devient répétitif et ennuyeux pour le chien.', 'Commencer dans un environnement calme et sans distractions. Augmenter progressivement les distractions et la complexité de l''environnement. Introduire des changements de rythme et de direction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/flanking.png'),
('flyball-intro', 'Le Flyball est un sport d''équipe excitant pour les chiens qui combine vitesse, agilité et obéissance. Il s''agit d''une course de relais où les chiens doivent récupérer une balle sur une station de Flyball et la ramener à leur propriétaire le plus rapidement possible. Cet exercice est idéal pour canaliser l''énergie de votre chien et renforcer votre lien à travers une activité ludique et stimulante.', NULL, NULL, 'Flyball introduction', 'Courir, déclencher la boîte, rapporter', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien déclenche la station sans aide, récupère la balle et revient systématiquement vers le propriétaire avec la balle, démontrant de l''enthousiasme et de la compréhension de l''exercice.', 'Le chien montre des signes de fatigue excessive, de frustration, ou si une douleur est suspectée. Le jeu doit toujours rester une expérience positive pour le chien. Arrêter également si le chien développe de l''anxiété ou un comportement d''évitement.', 'Commencer avec un chien motivé par la balle. S''assurer que le chien comprend l''objectif de la station et peut la déclencher. Le chien doit ramener la balle à chaque essai avant de passer à des étapes plus complexes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/flyball-intro.png'),
('focus-pres-stimulus', 'L''exercice ''Focus près du stimulus'' vise à apprendre à votre chien à rester calme et concentré sur vous, même en présence d''éléments distracteurs intenses. Il est essentiel pour développer l''autocontrôle de votre chien et renforcer votre lien. Cet exercice prolonge progressivement la durée de concentration du chien tout en augmentant le niveau de distraction.', NULL, NULL, 'Focus près du stimulus', 'Maintenir l''attention malgré le déclencheur', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore activement le stimulus et maintient un regard fixe et attentif sur vous pendant la durée demandée, même dans des environnements de plus en plus distrayants et à des distances réduites du stimulus.', 'Le chien montre des signes de stress, d''agressivité, d''évitement ou de peur. Toute perte de contrôle de la situation ou si l''exercice devient une source de frustration excessive pour le chien.', 'Observer le comportement du chien en présence de différentes distractions. Le chien doit pouvoir maintenir un contact visuel avec le propriétaire pendant un minimum de 15 secondes, même si le stimulus est présent et actif à proximité.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/focus-pres-stimulus.png'),
('fouille-batiment', 'La fouille de bâtiment est un exercice d''olfaction qui consiste à entraîner votre chien à rechercher une odeur spécifique (généralement une substance de recherche comme la résine de pin ou autre) dans un environnement contrôlé. Cet exercice développe les capacités naturelles de pistage de votre chien, renforce votre lien et stimule mentalement et physiquement l''animal. C''est une activité ludique et exigeante qui peut être adaptée à différents niveaux de difficulté.', NULL, NULL, 'Fouille de bâtiment', 'Inspecter un bâtiment pièce par pièce', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement l''odeur cible, la localise de manière fiable dans différents environnements et signale sa découverte (si applicable) de manière consistante et rapide.', 'Arrêtez l''exercice si le chien montre des signes de stress, de fatigue excessive, de blessure, ou de démotivation marquée. Assurez-vous que l''activité reste positive et stimulante pour votre chien.', 'Des séances régulières de 2 à 3 fois par semaine, d''une durée de 15 à 30 minutes, sont recommandées. Variez les environnements et les types de recherches pour maintenir l''intérêt et développer les compétences du chien.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/fouille-batiment.png'),
('franchissement-obstacles', 'Le franchissement d''obstacles est un excellent exercice pour renforcer la confiance de votre chien, améliorer sa coordination et son agilité. Il permet également de canaliser son énergie et de développer une communication plus fine entre vous et lui. Cet exercice peut être adapté à tous les chiens, peu importe leur taille ou leur race, et peut être réalisé avec du matériel simple ou acheté.', NULL, NULL, 'Franchissement d''obstacles', 'Naviguer dans des décombres instables', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien aborde l''obstacle avec confiance et sans hésitation, le franchit proprement sur commande verbale, et démontre une attitude positive et joyeuse pendant l''exercice.', 'Le chien montre des signes clairs de stress, de peur ou de fatigue excessive (halètement incontrôlable, tremblements, oreilles basses, queue rentrée, refus de s''approcher). Une blessure potentielle ou une douleur manifeste.', 'Observer la volonté du chien à approcher l''obstacle. Noter le nombre de tentatives nécessaires. Évaluer la qualité du franchissement (fluide, hésitant, peur). Vérifier la réceptivité aux commandes vocales et aux récompenses.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/franchissement-obstacles.png'),
('frisbee-base', 'Apprenez à votre chien à attraper et rapporter un frisbee. Cet exercice développe l''agilité, la coordination et renforce le lien entre vous et votre chien. Il est idéal pour les chiens actifs qui aiment jouer et courir.', NULL, NULL, 'Frisbee base', 'Attraper un frisbee lancé court', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien attrape le frisbee lancé à au moins 10 mètres, rapporte immédiatement et le lâche sur commande, répété 5 fois consécutives sans hésitation.', 'Le chien montre des signes de fatigue évidente, de stress, d''agacement, ou s''il refuse catégoriquement de participer malgré les encouragements.', 'Avant de lancer le frisbee, le chien doit être en position d''attente. Le chien doit attraper le frisbee en vol ou au premier rebond. Le chien doit ramener le frisbee sans hésitation et le lâcher sur commande à proximité du handler.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/frisbee-base.png'),
('frisbee-avance', 'Le Frisbee Figures Avancées est un sport canin dynamique qui pousse les compétences de base du frisbee à un niveau supérieur. Il implique des réceptions acrobatiques, des sauts impressionnants et une coordination accrue entre le chien et son maître. Cet exercice est idéal pour les chiens athlétiques et leurs propriétaires qui cherchent à relever de nouveaux défis ensemble, renforçant ainsi leur lien et leur confiance mutuelle.', NULL, NULL, 'Frisbee figures avancées', 'Sauts et figures au frisbee', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien montre de l''enthousiasme et de l''engagement pendant toute la séance, exécute des sauts et des réceptions en vol avec confiance, et rapporte le frisbee volontairement. La fluidité des mouvements et la coordination avec le maître sont visibles.', 'Le chien montre des signes de fatigue excessive (halètement important, ralentissement, refus de jouer), de stress ou d''inconfort. Toute blessure suspectée, même légère, doit immédiatement mettre fin à la séance.', 'Le chien doit réussir à attraper le frisbee lancé en l''air au moins 3 fois sur 5 lors de tentatives impliquant un saut modéré. Il doit également rapporter le frisbee au maître de manière autonome après chaque capture réussie.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/frisbee-avance.png'),
('front-cross', 'Le ''Front Cross'' est une technique d''agilité où le conducteur traverse devant son chien pour le diriger vers le prochain obstacle. Cela permet de maintenir le chien sous contrôle tout en lui offrant une liberté de mouvement optimale. Cet exercice est essentiel pour optimiser le flux et la vitesse sur un parcours d''agilité.', NULL, NULL, 'Front cross', 'Changement de côté par l''avant', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit l''obstacle de façon fluide et rapide à chaque ''Front Cross'' exécuté, sans hésitation. Le conducteur contrôle le mouvement efficacement sans tirer sur la laisse.', 'Le chien montre des signes de stress, de fatigue excessive, ou de frustration. Le conducteur ressent une douleur physique. L''exercice devient répétitif et improductif.', 'Exécuter 5 ''Front Cross'' consécutifs sans faute lors de l''introduction à un saut, puis 5 fois enchaînés avec un deuxième obstacle. Le chien doit franchir l''obstacle chaque fois sous l''impulsion du ''cross''.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/front-cross.png'),
('frustration-porte', 'Cet exercice vise à apprendre à votre chien à rester calme et assis devant une porte fermée, résistant à l''envie de se précipiter dehors dès qu''elle s''ouvre. Il est essentiel pour renforcer le contrôle de soi et prévenir les comportements impulsifs lors des entrées et sorties. La clé est la patience et une progression graduelle pour bâtir une association positive avec l''attente.', NULL, NULL, 'Frustration à la porte', 'Attendre calmement l''ouverture de la porte', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste assis calmement et sansLatency pendant toute l''ouverture de la porte et jusqu''à ce qu''il soit invité à sortir ou que la porte soit refermée.', 'Le chien panique, devient incontrôlable, ou montre des signes de stress importants et persistants malgré les ajustements.', 'Effectuer l''exercice 5 fois par jour, en variant les moments (avant les sorties, après les siestes, etc.) pendant une semaine.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/frustration-porte.png'),
('frustration-barriere', 'L''exercice de la frustration derrière une barrière enseigne à votre chien à gérer son excitation et à rester calme lorsqu''il est séparé de vous ou d''un congénère par un obstacle. Il est particulièrement utile pour les chiens qui ont tendance à aboyer, à sauter ou à devenir anxieux lorsqu''ils ne peuvent pas atteindre ce qu''ils désirent. Une application régulière de cet exercice renforce la patience et l''autocontrôle de votre chien, le rendant plus serein dans diverses situations.', NULL, NULL, 'Frustration derrière barrière', 'Rester calme derrière une barrière', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien parvient à détourner son attention de la distraction et à se calmer (moins de vocalisations, mouvements moins intenses) pendant au moins 10-15 secondes, de manière répétée, avant que la distraction ne soit retirée ou que le chien ne soit récompensé pour son calme.', 'Le chien montre des signes de stress excessif, de peur, d''agressivité ou de détresse qui ne s''améliorent pas malgré la réduction de l''intensité. Si le chien blesse le manipulateur ou la distraction, ou si la barrière est endommagée. Si l''exercice devient une source de traumatisme pour le chien.', 'Observer le chien pendant la présence de la distraction. Noter la durée et l''intensité des comportements de frustration (aboiements, grognements, sauts, grattements). Noter la durée pendant laquelle le chien parvient à se calmer seul ou avec une légère indication verbale (''Calme'').', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/frustration-barriere.png'),
('zen-bowl', 'La Gamelle Zen est un exercice d''éducation canine qui enseigne au chien la patience et l''auto-contrôle face à une récompense très désirable, sa nourriture. En lui apprenant à attendre calmement son repas, vous renforcez son obéissance et réduisez les comportements impulsifs liés à l''alimentation. Cet exercice est idéal pour canaliser son énergie et construire une relation de confiance mutuelle.', NULL, NULL, 'Gamelle zen', 'Manger calmement avec patience', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien attend de manière calme et contenue le signal de libération, même lorsque la gamelle est à portée de museau, pendant au moins 30 secondes dans un environnement familier.', 'Le chien montre des signes de stress excessif, d''agressivité, ou tente de mordre la gamelle ou la main. L''exercice doit être interrompu jusqu''à ce que le chien soit apaisé et que le problème soit résolu.', 'Observer que le chien maintient une position basse (assis ou couché) et un regard calme, sans vocaliser ni tenter de sauter sur la gamelle pendant toute la durée de l''attente.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/zen-bowl.png'),
('garde-au-ferme', 'L''exercice de ''Garde au ferme'' enseigne au chien à rester immobile dans une position donnée, même en présence de distractions. Cet exercice est fondamental pour développer l''autocontrôle et la concentration du chien. Il est essentiel pour des situations où le chien doit attendre patiemment, comme à la porte ou lors d''une visite.', NULL, NULL, 'Garde au ferme', 'Aboyer face au figurant immobile', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien reste immobile sur commande (''Reste'') pendant une durée de 1 à 2 minutes avec des distractions raisonnables, et relâche la position uniquement sur ordre (''Viens'' suivi d''une récompense).', 'Le chien se lève de façon répétée malgré les corrections verbales douces ou les encouragements, tente activement d''attraper un objet lancé, ou montre des signes de stress excessif (halètement, bâillements répétés, tentatives de fuite).', 'Observer si le chien reste immobile dans la position demandée (couché ou assis) pendant au moins 30 secondes malgré des distractions modérées (bruits, mouvements du maître, passage d''une personne à distance). Le chien ne doit pas se lever, changer de position, ni chercher activement à interagir avec la distraction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/garde-au-ferme.png'),
('garde-objet', 'Cet exercice vise à apprendre au chien à rester immobile à côté d''un objet de valeur, sans le toucher ni le voler. C''est une excellente base pour le contrôle de soi et la prévention du vol d''objets. Il demande patience et constance de la part du propriétaire.', NULL, NULL, 'Garde d''objet', 'Garder un objet et le défendre', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore l''objet même lorsque le propriétaire fait des bruits ou des mouvements modérés, et ne bouge que sur l''ordre de retour.', 'Arrêter si le chien montre des signes de stress excessif, de frustration ou d''agressivité. Reprendre plus tard ou simplifier l''exercice.', 'L''exercice est validé lorsque le chien reste immobile à côté de l''objet pendant au moins 30 secondes lorsque le propriétaire est à 2 mètres, sans tenter de prendre l''objet.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/garde-objet.png'),
('garde-statique', 'La garde statique est un exercice fondamental pour développer l''autocontrôle et la patience chez le chien. Il enseigne au chien à rester immobile dans une position donnée, même en présence de distractions. Cet exercice renforce également la confiance entre le propriétaire et le chien, car il repose sur une communication claire et le respect mutuel.', NULL, NULL, 'Garde statique', 'Garder un point sans bouger', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien reste immobile sur commande pendant la durée demandée, ignore les distractions mineures (bruit faible, objet tombé loin de lui), et ne se lève qu''après le signal de libération clair. Le chien semble détendu et confiant.', 'Le chien quitte sa position initiale de manière répétée malgré les instructions. Le chien montre des signes de stress importants (halètement excessif, tremblements, bâillements frénétiques, tentative de fuite). L''exercice devient une source de frustration pour le chien ou le propriétaire.', 'Pour valider l''exercice, le chien doit rester immobile dans la position demandée pendant au moins 30 secondes, malgré des distractions légères et contrôlées. Le propriétaire doit pouvoir s''éloigner de quelques mètres sans que le chien ne bouge.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/garde-statique.png'),
('gauche-droite', 'L''exercice ''Gauche/Droite'' apprend au chien à tourner sur lui-même dans une direction spécifique sur commande verbale. Cet exercice améliore la proprioception du chien, sa concentration et renforce la communication entre le maître et l''animal. C''est une base utile pour des tours plus complexes et une bonne gestion du contrôle dans des environnements distrayants.', NULL, NULL, 'Gauche/Droite', 'Distinguer gauche et droite', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien effectue un tour complet sur lui-même dans la direction demandée (gaucher ou droitier) en réponse à la commande verbale seule, sans aide de leurrage, sur 8/10 répétitions.', 'Le chien montre des signes de stress (bâillements excessifs, halètements non liés à l''effort, queue basse, oreilles en arrière), de fatigue physique, ou si vous constatez que la frustration augmente des deux côtés après plusieurs essais.', 'Demander ''Gauche'' et vérifier que le chien tourne sur lui-même dans le sens horaire (vue de dessus). Demander ''Droite'' et vérifier que le chien tourne sur lui-même dans le sens antihoraire. L''exercice doit être fluide et compris sans hésitation. Tester avec et sans friandise visible (leurre caché dans la main).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gauche-droite.png'),
('gerer-competition', 'Cet exercice vise à apprendre à votre chien à rester calme et patient en présence de nourriture, même lorsqu''elle est hors de sa portée. Il est essentiel pour prévenir les comportements agressifs liés à la nourriture et renforcer votre complicité. Une bonne gestion de la compétition alimentaire assure la sécurité de tous et le bien-être de votre chien.', NULL, NULL, 'Gérer la compétition alimentai', 'Rester calme quand un autre chien mange', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien peut attendre patiemment et calmement devant une gamelle de nourriture ou une friandise sans grogner, aboyer ou tenter de l''attraper. Il attend le signal verbal pour manger ou recevoir la friandise.', 'Le chien montre des signes de stress importants, d''excitation excessive, d''agressivité ou de peur. La frustration devient trop grande et l''exercice devient contre-productif. Arrêtez la séance et revenez à une étape plus simple ou arrêtez pour la journée.', 'Commencez par des sessions courtes (5-10 minutes) plusieurs fois par jour. L''objectif est que le chien associe la présence de nourriture (ou la gamelle) à l''attente et au calme. Augmentez progressivement la durée et la difficulté des exercices.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gerer-competition.png'),
('gerer-visiteurs', 'Cet exercice vise à apprendre à votre chien à rester calme et respectueux lorsqu''une personne entre dans votre domicile. Il s''agit d''un entraînement essentiel pour éviter les sauts, les aboiements excessifs et l''anxiété lors des visites. Une bonne gestion des visiteurs améliore la sécurité et le confort de tous.', NULL, NULL, 'Gérer les visiteurs', 'Rester calme quand des gens arrivent', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, assis ou couché, même à l''ouverture de la porte et à l''entrée du visiteur. Il ne saute pas, n''aboie pas excessivement et ne montre pas de signe d''agitation incontrôlable. Il peut interagir calmement avec le visiteur si celui-ci le lui propose après quelques minutes.', 'Le chien panique, se montre agressif, ne répond plus aux commandes de base, ou la situation devient ingérable pour le propriétaire. Arrêter immédiatement l''exercice et revenir à une étape plus simple ou considérer une aide professionnelle.', 'Observer la réaction du chien à chaque étape. Le visiteur doit entrer calmement et sans interaction initiale, laissant le chien gérer la situation sous contrôle du propriétaire. Les récompenses sont données lorsque le chien maintient la réussite de l''étape.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gerer-visiteurs.png'),
('gerer-bruit-soudain', 'Cet exercice vise à désensibiliser votre chien aux bruits soudains et inattendus, réduisant ainsi ses réactions de peur ou d''anxiété. L''objectif est de lui apprendre que ces bruits ne représentent pas une menace. Une approche progressive et positive est essentielle pour bâtir la confiance de votre chien.', NULL, NULL, 'Gérer un bruit soudain', 'Récupérer rapidement après un bruit fort', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien montre une réaction minimale ou nulle à des bruits soudains d''intensité modérée et peut continuer une activité normale (jouer, manger, interagir) peu de temps après leur apparition. Il n''émet plus de signes de peur ou de panique.', 'Le chien montre des signes de stress importants, de panique, de agressivité ou une volonté de fuite irrésistible. Si le chien est glucosé ou a des problèmes de santé qui pourraient être exacerbés par le stress.', 'Observer la réaction du chien : absence de peur (pas de queue entre les pattes, pas de halètement excessif, pas de recherche de fuite). Le chien doit faire le lien entre le bruit et une récompense positive, ou du moins rester neutre.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gerer-bruit-soudain.png'),
('gestion-peur', 'Cet exercice vise à aider votre chien à surmonter ses peurs face à des stimuli spécifiques. L''objectif est de désensibiliser progressivement le chien et de créer des associations positives. Une approche calme et patiente est essentielle pour le succès.', NULL, NULL, 'Gestion de la peur', 'Approcher un objet effrayant', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien montre de la curiosité, un comportement calme, voire de l''indifférence face au stimulus, et recherche activement des récompenses en sa présence.', 'Arrêtez la session immédiatement si le chien montre des signes de stress majeur, de panique ou d''agressivité. La sécurité et le bien-être du chien priment toujours.', 'La désensibilisation est réussie lorsque le chien peut supporter la présence du stimulus à une distance raisonnable sans manifester de signes de stress (halètement excessif, tremblements, tentatives de fuite, vocalises).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gestion-peur.png'),
('gestion-fenetre', 'Cet exercice vise à aider votre chien à rester calme et détendu lorsqu''il observe le monde extérieur depuis une fenêtre. L''objectif est de réduire les réactions excessives telles que les aboiements, les grognements ou l''agitation. Nous allons travailler sur l''association positive avec ce qui se passe dehors en apprenant au chien des comportements alternatifs.', NULL, NULL, 'Gestion de la réactivité à la ', 'Arrêter d''aboyer à la fenêtre', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien regarde par la fenêtre sans aboyer pendant au moins 10 secondes, ou revient à un comportement calme (ex: s''asseoir, mâchouiller un jouet) dans les 5 secondes après avoir vu une distraction.', 'Le chien montre des signes de stress excessif (halètement excessif, tremblements, tentatives de fuite) malgré les interventions, indiquant que la situation est trop difficile pour l''instant. Arrêtez l''exercice et revenez à une étape plus simple.', 'Évaluer la capacité du chien à rester calme ou à revenir au calme rapidement dans différentes situations de fenêtre, avec diverses distractions.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/gestion-fenetre.png'),
('trigger-stacking', 'Le ''trigger stacking'' décrit l''accumulation de plusieurs petits stresseurs qui, individuellement, ne déclencheraient pas une réaction, mais dont la superposition mène à une réponse disproportionnée ou incontrôlable du chien. Cet exercice vise à aider le chien à mieux gérer ces situations en lui apprenant à rester calme et à reconnaître quand il atteint ses limites. L''objectif est de prévenir l''explosion comportementale et de renforcer la confiance du binôme.', NULL, NULL, 'Gestion du trigger stacking', 'Reconnaître l''accumulation de stress', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de rester calme et de ne pas réagir de manière excessive (pas d''aboiements, grognements, panique, fuite) lorsque deux déclencheurs sont simultanément présents à une distance et intensité raisonnables qui étaient préalablement problématiques. Il montre des signes de détente ou de neutralité.', 'Le chien montre des signes évidents de stress croissant malgré la réduction de l''intensité ou l''augmentation de la distance (ex: halètement excessif, tremblements, vocalises, tentatives de fuite répétées, rigidité corporelle). Cela indique qu''il a dépassé sa capacité de gestion dans cette session.', 'Observer la capacité du chien à rester détendu (respiration calme, corps non rigide, pas de symptômes de stress majeurs) en présence de un ou deux déclencheurs identifiés, à une distance et intensité définies, pendant au moins 5 minutes. Récompenser les moments de calme et de neutralité.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/trigger-stacking.png'),
('desens-voiture-trajet', 'Cet exercice vise à habituer votre chien à la voiture, en le rendant confortable et détendu lors des trajets. L''objectif est de créer une association positive avec le véhicule afin d''éviter l''anxiété ou la peur. Une bonne habituation rendra les déplacements plus agréables pour vous deux. Cette méthode progressive est cruciale pour les chiens sensibles.', NULL, NULL, 'Habituation à la voiture', 'Accepter les trajets en voiture', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien monte dans la voiture volontairement, reste calme pendant les courts trajets, et n''exprime pas de signes d''anxiété, de peur ou de mal des transports.', 'Le chien montre une détresse significative (halètements intenses, tremblements, agressivité, tentatives de fuite désespérées) à n''importe quelle étape. Si le mal des transports est présent, arrêtez le trajet et consultez un vétérinaire.', 'Commencez par des séances courtes et positives autour de la voiture à l''arrêt. Progressez vers l''entrée dans la voiture, puis des périodes courtes à l''intérieur moteur éteint. Terminez par de très courts trajets. Récompensez chaque progrès et chaque signe de calme.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-voiture-trajet.png'),
('habituation-bruits', 'L''habituation aux bruits est essentielle pour qu''un chien se sente à l''aise dans divers environnements. Cet exercice permet de prévenir les réactions de peur ou d''anxiété face aux sons inhabituels. Une bonne habituation favorise un chien plus confiant et équilibré.', NULL, NULL, 'Habituation aux bruits', 'Exposer progressivement aux bruits courants', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et détendu en présence du son cible, sans montrer de signes de stress ou d''anxiété, même à un volume raisonnablement élevé.', 'Le chien montre une détresse significative, tente de fuir, ou ne parvient pas à se détendre malgré la réduction du volume et les récompenses.', 'Observer attentivement le langage corporel du chien pendant et après l''exposition au son. Utiliser des enregistrements de différents types et intensités de bruits.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/habituation-bruits.png'),
('enfants', 'L''habituation aux enfants est un processus crucial pour qu''un chien développe une relation positive et sereine avec les plus jeunes. Cet exercice vise à désensibiliser le chien aux bruits, mouvements et comportements typiques des enfants, tout en lui apprenant à rester calme et confiant. Une bonne habituation prévient les réactions de peur ou d''agression et favorise une cohabitation harmonieuse et sécuritaire.', NULL, NULL, 'Habituation aux enfants', 'Rester calme en présence d''enfants', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et neutre en présence d''enfants, peut tolérer leur présence à proximité, et montre des signes de bien-être. Il ne manifeste plus de peur ou d''excitation excessive.', 'Le chien montre des signes de stress marqués (anxiété, peur, agressivité), le contact devient trop intense pour le chien, ou les enfants ne suivent pas les consignes de sécurité.', 'Observer attentivement le langage corporel du chien. S''il est détendu, curieux sans être anxieux, et réceptif aux récompenses, l''exercice est probablement bien accepté.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/enfants.png'),
('barriere-bebe', 'Cet exercice vise à habituer votre chien à la présence d''un bébé, en particulier lorsqu''il est dans une barrière de sécurité. L''objectif est d''associer la barrière et la présence du bébé à des expériences positives pour le chien. Cela permet de prévenir toute anxiété ou réactivité future du chien envers le bébé.', NULL, NULL, 'Habituation barrière bébé', 'Accepter la séparation par barrière', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien peut rester calme et détendu dans la même pièce que la barrière avec le bébé derrière, même à courte distance (ex: 1 mètre), sans tentatives d''approche, d''aboiements excessifs ou de signes de stress.', 'Arrêtez immédiatement l''exercice si le chien montre des signes de stress importants, de peur, d''agressivité ou de frustration accrue. Reprenez l''exercice à une étape plus facile ou réduisez la durée. Ne jamais forcer le chien à interagir.', 'Chaque session doit se terminer sur une note positive pour le chien, sans montrer de signes de stress ou de réactivité envers la barrière ou le bébé. La progression doit être lente et adaptée au rythme du chien.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/barriere-bebe.png'),
('helicoptere-habituation', 'Cet exercice vise à habituer progressivement votre chien aux bruits et aux mouvements d''un hélicoptère, qui peuvent être sources de stress. L''objectif est de créer une association positive avec cette situation potentiellement effrayante. Il est crucial de procéder par étapes et de respecter le rythme de votre chien pour garantir son bien-être.', NULL, NULL, 'Habituation hélicoptère', 'Rester calme près d''un hélicoptère', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de rester calme et détendu avec un son d''hélicoptère diffusé à un volume réaliste et à proximité, et réagit de manière neutre lors de mouvements simulés. Il ne manifeste plus de signes d''anxiété ou de peur face à cette situation.', 'Si le chien montre des signes répétés et intenses de peur, de panique, d''agressivité ou de fuite malgré tous les ajustements. Si l''exercice devient une source de stress chronique pour le chien. Si le propriétaire se sent dépassé ou incapable de gérer la situation en toute sécurité.', 'Pour valider chaque étape, le chien doit montrer des signes de détente et de curiosité, ou au minimum une absence de peur ou de réaction de fuite, pendant toute la durée de la session. Le chien doit pouvoir se concentrer sur le propriétaire malgré le stimulus visuel et auditif.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/helicoptere-habituation.png'),
('high-five', 'Le High Five est un trick amusant qui renforce la connexion entre vous et votre chien. Il enseigne la coordination et la proprioception à votre compagnon. C''est un excellent jeu d''interaction pour les jours de pluie ou les moments calmes.', NULL, NULL, 'High five', 'Taper dans la main levée', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien lève et pose sa patte sur la main tendue de l''humain dans les 3 secondes suivant la commande "High five !" et ce, dans 80% des essais sur 10 essais consécutifs.', 'Arrêter l''exercice si le chien montre des signes de stress, de frustration, d''agressivité, ou s''il est incapable de se concentrer sur la tâche après plusieurs minutes de pratique.', 'Ce protocole valide l''apprentissage du trick "High Five" lorsque le chien initie le contact de sa patte avec la main tendue de l''humain en réponse à la commande vocale.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/high-five.png'),
('hoopers', 'Le Hoopers est un sport canin où le chien parcourt un parcours d''obstacles à distance, guidé par son maître via des commandes vocales et des mouvements corporels. Il est idéal pour les chiens de tous âges et de toutes races, ainsi que pour les maîtres qui ne peuvent pas courir. L''objectif est de développer la communication et la complicité entre le chien et son propriétaire dans un environnement ludique et sans stress.', NULL, NULL, 'Hoopers', 'Parcours de cerceaux et tunnels à distance', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit tous les obstacles du parcours dans le bon ordre et dans le sens indiqué, avec enthousiasme et sans hésitation, guidé par les indications de son maître.', 'Le chien montre des signes de stress, de fatigue excessive, de blessure, ou si le maître perd sa patience ou sa motivation. Arrêter également si le chien ne progresse plus malgré les ajustements.', 'Observer la compréhension du chien des commandes et des gestes, sa fluidité à travers le parcours, et sa motivation à collaborer avec le maître.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/hoopers.png'),
('hydro-senior', 'L''exercice canin ''Hydro Senior'' est conçu spécifiquement pour les chiens âgés ou ceux ayant des problèmes articulatoires légers. Il s''agit d''une activité aquatique douce qui vise à maintenir la mobilité, renforcer les muscles sans surmenage et améliorer le bien-être général de votre compagnon senior. L''eau offre une portance qui soulage la pression sur les articulations, rendant l''exercice plus confortable et moins douloureux pour les chiens vieillissants.', NULL, NULL, 'Hydro senior', 'Marche en eau pour les articulations', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien entre dans l''eau sans anxiété marquée, participe activement à l''exercice pendant la durée prévue, donne des signes de plaisir ou de détente, et sort sans raideur ou inconfort visible.', 'Le chien montre une peur intense, une résistance persistante, un halètement excessif, des tremblements, des signes de douleur ou de fatigue extrême, ou tout autre signe de mal-être.', 'Observer la réaction du chien à l''entrée dans l''eau, son comportement lors du déplacement, sa réponse aux commandes vocales et sa réaction à la sortie (absence de gêne).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/hydro-senior.png'),
('hydrothérapie', 'L''hydrothérapie pour chiens est une forme de physiothérapie qui utilise l''eau pour favoriser le mouvement et la guérison. Elle est particulièrement bénéfique pour les chiens souffrant de problèmes articulaires, de blessures musculaires ou en convalescence après une chirurgie. L''eau offre une résistance douce, ce qui permet de renforcer les muscles sans stress excessif sur les articulations.', NULL, NULL, 'Hydrothérapie', 'Exercice thérapeutique en eau', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien participe activement et sereinement à l''hydrothérapie, montre une amélioration de sa mobilité, de sa force musculaire ou de sa récupération, et semble moins stressé par l''eau au fil des séances.', 'Le chien montre des signes évidents de douleur, de stress extrême, de fatigue excessive, ou refuse catégoriquement de participer malgré les encouragements. Toute aggravation de sa condition médicale doit entraîner l''arrêt immédiat.', 'Observer attentivement le comportement du chien pendant et après la séance. Noter toute hésitation, peur, douleur ou au contraire, enthousiasme et facilité de mouvement. Consulter le vétérinaire ou le physiothérapeute pour un avis professionnel sur la progression.', 'Observer le langage corporel', NULL, NULL, 'tous', NULL),
('ignorer-depart', 'Cet exercice vise à apprendre à votre chien à ignorer les signaux de départ lorsqu''il est en phase d''attente. Il est crucial pour développer l''autocontrôle et la concentration de votre chien, même en présence de distractions. La réussite de cet exercice renforce la confiance mutuelle et prépare le chien à des environnements plus complexes et stimulants.', NULL, NULL, 'Ignorer les signaux de départ', 'Ne plus stresser quand vous prenez les clés', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste immobile sur place sans bouger, même en présence de distractions modérées, jusqu''à ce qu''un signal de départ clair soit donné. Moins de 10% de faux départs lors des séances d''entraînement.', 'Le chien montre des signes de stress ou de frustration évidents (halètement excessif, tentatives de fuite, agressivité). L''exercice devient une source de conflit au lieu d''un apprentissage positif.', 'Lors de chaque séance, notez le nombre de faux départs par rapport au nombre de signaux lancés. Comptez également le temps pendant lequel le chien reste immobile sans signal.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ignorer-depart.png'),
('ignore-nourriture-sol', 'Cet exercice vise à apprendre à votre chien à ignorer la nourriture laissée au sol, une compétence cruciale pour sa sécurité et pour prévenir les comportements indésirables. Il renforce l''autocontrôle et la confiance entre vous et votre chien, tout en lui enseignant que vous êtes la source principale de récompenses. Une bonne exécution de cet exercice contribue à un chien plus serein et obéissant en promenade.', NULL, NULL, 'Ignorer nourriture au sol', 'Ne pas ramasser lors de la promenade', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore systématiquement toute nourriture au sol et attend votre permission pour manger ou ignore complètement le reste de la nourriture après l''ordre ''Laisse''.', 'Le chien est irritable, effrayé ou montre des signes de stress excessif. Le chien refuse de coopérer et devient hors de contrôle.', 'Sur une période de 2 semaines, répétez l''exercice 3 fois par jour pour un total de 5 à 10 minutes par session. Variez les lieux et les types de nourriture jetée au sol.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ignore-nourriture-sol.png'),
('jouet-interdit', 'Cet exercice enseigne au chien à ignorer un jouet particulièrement attrayant, même lorsqu''il est à portée. Il est essentiel pour renforcer le contrôle de soi et la confiance en votre leadership. Réussir cet exercice permet de gérer plus facilement les distractions dans des environnements riches en stimuli.', NULL, NULL, 'Ignorer un jouet interdit', 'Ne pas toucher un jouet posé devant lui', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore le jouet intentionnellement lorsqu''il en reçoit l''ordre, et se tourne vers le propriétaire pour obtenir une récompense. La durée d''ignorance augmente graduellement.', 'Le chien attrape ou mordille le jouet malgré l''ordre, ou si le chien devient anxieux ou frustré. Il faut alors revenir à une étape plus facile.', 'Après quelques sessions réussies à courte distance, augmentez progressivement la distance et la durée pendant lesquelles le chien doit ignorer le jouet. Introduisez des jouets plus tentants et des environnements plus distrayants.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jouet-interdit.png'),
('indication-active', 'Cet exercice apprend à votre chien à indiquer activement un besoin ou une envie, que ce soit pour sortir, manger, jouer ou nécessiter votre attention. Il permet d''éviter les comportements indésirables comme les miaulements ou les grattages intempestifs en canalisant ces besoins. C''est un excellent outil pour améliorer la communication et renforcer le lien entre vous et votre compagnon.', NULL, NULL, 'Indication active (gratter/abo', 'Signaler la trouvaille activement', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien utilise l''indication, sur commande ou spontanément, pour signaler un besoin environ 9 fois sur 10 lors des séances d''entraînement. Il est capable de généraliser cette indication à différentes situations et besoins.', 'Le chien montre des signes de stress, de peur, d''agressivité ou de désintérêt prononcé pour l''exercice. Si l''exercice devient une source de frustration pour le chien ou pour le propriétaire, il est préférable de s''arrêter et de consulter un professionnel.', 'Le chien doit utiliser le signal appris (gratter ou aboyer) de manière autonome pour exprimer un besoin clair (ex: vouloir sortir, manger, jouer) et obtenir la récompense attendue. L''indication doit être proactive et non une réaction à une sollicitation directe du propriétaire.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/indication-active.png'),
('indication-marquage-pro', 'Cet exercice enseigne au chien à identifier un objet spécifique parmi plusieurs et à le marquer, que ce soit par un regard, une patte ou un mordillement léger. Il est essentiel pour les sports canins comme le pistage ou le mantrailing, mais aussi pour renforcer la complicité et la compréhension mutuelle. La précision et la motivation du chien sont les clés de la réussite de cet apprentissage.', NULL, NULL, 'Indication et marquage pro', 'Signaler la trouvaille selon le protocole', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien sélectionne l''objet désiré dans 90% des cas avec au moins trois objets distracteurs et marque de façon claire et intentionnelle.', 'Le chien montre des signes de stress, de frustration ou de fatigue excessive. Si le chien ne parvient pas à faire le comportement dans les 20 tentatives ou s''il commence à éviter le handler ou l''exercice.', 'Observer que le chien identifie correctement l''objet cible parmi des distracteurs et effectue le marquage appris de manière répétée et fiable.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/indication-marquage-pro.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('indication-aboiement', 'Cet exercice apprend au chien à aboyer sur commande, utile pour la garde ou pour signaler quelque chose. Il se pratique en plusieurs étapes pour un apprentissage progressif et efficace, en renforçant positivement le comportement désiré. L''objectif est d''obtenir un aboiement contrôlé et uniquement lorsque vous le demandez.', NULL, NULL, 'Indication par aboiement', 'Aboyer en continu sur la victime', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien aboie une à trois fois de manière contrôlée lorsqu''on lui donne le mot-clé ''Parle !'' et se tait immédiatement sur le signal ''Stop !'' dans au moins trois environnements différents avec des distractions modérées.', 'Le chien montre des signes de stress (lèchements, bâillements répétés, queue basse), aboiement excessif et incontrôlable, ou une absence totale de réaction malgré les efforts répétés.', 'Après avoir atteint l''étape 3, demander ''Parle !'' dans un environnement calme. Le chien doit aboyer une ou deux fois. Puis, donner le signal ''Stop !'' et le chien doit se taire. Répéter dans différentes situations et valider la réaction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/indication-aboiement.png'),
('indication-passive', 'L''indication passive consiste à apprendre au chien à adopter une position assise ou couchée à la demande, sans que le propriétaire n''ait à manipuler physiquement l''animal. Cet exercice développe la concentration et le contrôle de soi du chien. Il est fondamental pour la construction d''un langage de communication clair entre le propriétaire et son chien.', NULL, NULL, 'Indication passive (sit/couché', 'Marquer la trouvaille en s''asseyant', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien s''assoit ou se couche sur commande vocale uniquement, en moins de 3 secondes, et maintient la position jusqu''à ce qu''il soit libéré.', 'Le chien montre des signes de stress, de fatigue excessive, d''ennui ou de frustration. Si l''exercice devient répétitif et non productif malgré plusieurs tentatives.', 'S''assurer que le chien s''assoit ou se couche de manière autonome et rapide (en moins de 3 secondes après le commandement vocal) dans 80% des cas sur 10 essais consécutifs, en l''absence de signaux gestuels humains.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/indication-passive.png'),
('mordillement', 'L''inhibition de la morsure apprend au chien à contrôler la force de sa mâchoire lorsqu''il joue ou interagit avec les humains. C''est une compétence essentielle pour prévenir les blessures accidentelles lors des interactions. Cet exercice favorise une relation harmonieuse et sécuritaire entre le chien et son propriétaire, ainsi qu''avec d''autres personnes et animaux.', NULL, NULL, 'Inhibition de la morsure', 'Apprendre à ne pas mordre', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chiot mordille de façon de plus en plus douce lors des interactions, s''arrête immédiatement après un cri aigu, et maintient le jeu plus longtemps sans mordre fort.', 'Le chiot montre des signes de stress, de peur ou d''agressivité. Le propriétaire se sent inconfortable ou incapable de gérer la situation.', 'Observer la réaction du chiot au cri, la durée de l''interruption du jeu, et la progressivité de la réduction de la force de la morsure sur une période de plusieurs jours.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/mordillement.png'),
('inspection-dents', 'L''inspection des dents de votre chien est cruciale pour sa santé bucco-dentaire et générale. Cette routine permet de détecter précocement des problèmes comme le tartre, la gingivite ou les dents cassées. Une manipulation douce et positive dès le plus jeune âge facilitera grandement cet examen.', NULL, NULL, 'Inspection des dents', 'Ouvrir la gueule pour vérification', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et coopératif pendant toute la durée de l''inspection (environ 5 minutes au total), permettant une visualisation claire de toutes les surfaces dentaires, sans montrer de signes de stress ou d''agressivité.', 'Le chien montre des signes clairs de stress ou de peur (halètement excessif, bâillements compulsifs, oreilles en arrière, corps raide, tentative de fuite) ou une agressivité manifeste. Toute douleur détectée chez le chien nécessite un arrêt immédiat et une consultation vétérinaire.', 'Documenter chaque session dans un carnet de suivi, notant la durée de la manipulation, la réaction du chien, et toute observation sur l''état des dents. Prévoir une inspection hebdomadaire et une inspection mensuelle plus approfondie.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/inspection-dents.png'),
('interpellation', 'L''interpellation est un exercice de contrôle où le chien doit s''arrêter net sur commande, peu importe ce qui se passe autour de lui. Cet exercice est fondamental pour la sécurité et le contrôle du chien dans diverses situations. Il est particulièrement utile pour prévenir les fuites et assurer la sécurité lors de promenades ou de situations potentiellement dangereuses.', NULL, NULL, 'Interpellation', 'Intercepter et maintenir un suspect', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien s''arrête instantanément à ma commande ''Stop'', même en mouvement vers une cible attrayante ou en présence de distractions modérées à fortes. Il reste immobile jusqu''à ce que je lui donne un autre ordre ou une libération.', 'Le chien montre des signes de stress excessif, de peur, d''agression, ou qu''il n''y a aucune amélioration malgré des ajustements répétés. Arrêter l''exercice et revenir à des acquis plus solides ou consulter un professionnel.', 'L''exercice est validé après 5 répétitions consécutives réussies dans un environnement donné avec un niveau de distraction donné, avant de passer à un environnement plus stimulant. Le chien doit s''arrêter dans les 1 à 2 secondes suivant la commande.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/interpellation.png'),
('intervention-interieur', 'L''exercice "Intervention en intérieur" vise à apprendre au chien à rester calme et obéissant dans un environnement domestique potentiellement distrayant. Il s''agit de renforcer les commandes de base (assis, couché, pas bouger) et l''autocontrôle face aux tentations du foyer. Cet exercice est fondamental pour une coexistence harmonieuse, car il éduque le chien à gérer son excitation et à respecter les règles au sein même de sa maison.', NULL, NULL, 'Intervention en intérieur', 'Agir dans des espaces confinés', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien répond immédiatement aux commandes malgré les bruits et mouvements habituels du foyer, maintient une position demandée pendant au moins 30 secondes à 1 mètre de distance, et ne cherche pas activement à atteindre des objets ou personnes distrayants. Il montre aucun signe de stress ou d''excitation excessive.', 'Le chien montre des signes de stress prononcé (halètement excessif, tremblements, tentatives de fuite), une agressivité défensive ou une peur panique. La séance doit également être arrêtée si l''éducateur ou le chien sont frustrés ou éreintés.', 'L''exercice est validé lorsque le chien exécute les commandes (assis, couché, pas bouger) de manière fiable en intérieur, malgré des distractions modérées, et qu''il manifeste un comportement calme et détendu dans la maison.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/intervention-interieur.png'),
('intro-detection', 'Cet exercice enseigne à votre chien à associer une odeur spécifique à une récompense, posant ainsi les bases de la recherche d''objets. Il stimule l''instinct naturel de pistage de votre compagnon et renforce votre lien à travers un jeu olfactif engageant. Une approche progressive est essentielle pour garantir que le chien comprenne le jeu et prenne plaisir à chercher.', NULL, NULL, 'Introduction à la détection', 'Associer une odeur cible à la récompense', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement et de manière autonome l''odeur à l''aide de son flair, réussissant à trouver l''objet dans 4 sur 5 cachettes de difficulté progressive, avec une attente maximale de 30 secondes par cachette.', 'Le chien montre des signes de stress, de frustration ou de désintérêt prononcé. Il refuse catégoriquement de chercher, ou il est distrait par d''autres stimuli. La répétition excessive de l''exercice sans succès peut aussi être un indicateur.', 'Sélectionnez 5 cachettes de difficultés variées dans une pièce. Présentez l''odeur, lancez le chien à la recherche. Chaque trouvaille doit être validée par une récompense et des félicitations. Observez la rapidité et la conviction du chien.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/intro-detection.png'),
('boudin-intro', 'L''exercice du boudin est un jeu d''enrichissement simple mais très efficace pour stimuler mentalement votre chien et lui apprendre à utiliser son flair. Il consiste à cacher des friandises dans un objet long et flexible, le ''boudin'', que le chien doit ensuite explorer pour les trouver. Cet exercice est idéal pour canaliser l''énergie de votre chien et renforcer votre lien.', NULL, NULL, 'Introduction au boudin', 'Première prise sur boudin de jute', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement le boudin, le manipule avec sa gueule et/ou ses pattes pour faire sortir les friandises, et réussit à en extraire la majorité de celles-ci. Le chien montre un engagement positif et une satisfaction visible après avoir trouvé ses récompenses.', 'Le chien ne montre plus d''intérêt pour le boudin, ou perd son excitation. L''exercice peut aussi s''arrêter lorsque toutes les friandises ont été extraites avec succès, ou si le chien manifeste des signes de frustration ou d''agressivité envers l''objet.', 'Observez si le chien montre de l''intérêt pour le boudin, s''il l''utilise activement pour tenter d''en extraire les friandises, et s''il parvient à en libérer au moins une par session. La recherche active et la manipulation du boudin sont des signes clés.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/boudin-intro.png'),
('clicker-chiot', 'L''introduction au clicker est une étape fondamentale pour établir une communication claire avec votre chiot. Cet exercice consiste à associer le son du clicker à une récompense positive, créant ainsi un signal que votre chiot apprendra à attendre avec anticipation. Cela pose les bases pour un entraînement futur basé sur le renforcement positif, rendant l''apprentissage de nouvelles commandes plus efficace et agréable pour votre compagnon.', NULL, NULL, 'Introduction au clicker (chiot', 'Associer le clic à la récompense', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chiot recherche activement le click et anticipe la récompense, en détournant son attention d''autres stimuli pour se concentrer sur le handler dès que le click retentit.', 'Le chiot montre des signes de fatigue, de stress, d''ennui (bâillements répétés, léchage des babines excessif, tentatives de fuite) ou s''agite de manière incontrôlable. Ne jamais forcer un chiot.', 'Observer si le chiot tourne la tête vers le handler et manifeste de l''anticipation (mobilité des oreilles, regard fixe) à chaque clic, même sans voir la friandise immédiatement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/clicker-chiot.png'),
('intro-troupeau', 'Cet exercice simule une interaction avec un troupeau pour initier le chien à ce concept. Il vise à développer des instincts de gestion tout en renforçant le lien avec le maître. Il est crucial de commencer dans un environnement contrôlé pour assurer la sécurité du chien et des "bétails".', NULL, NULL, 'Introduction au troupeau', 'Première exposition aux moutons', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien peut se déplacer autour d''un petit troupeau sans le perturber, en répondant aux commandes de base du maître (stop, approche). Le chien montre un comportement de gestion calme et réfléchi plutôt qu''une réaction instinctive de poursuite.', 'Le chien montre une peur intense, une agressivité incontrôlable, ou traumatise les animaux. Le maître ne parvient pas à maintenir le contrôle du chien, ou les animaux sont constamment en fuite ou paniqués.', 'Observer la réaction du chien face à la présence du troupeau. Le chien doit montrer de l''intérêt sans agressivité ni peur excessive. Les animaux doivent rester calmes et ne pas montrer de signes de stress majeurs.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/intro-troupeau.png'),
('manchette-intro', 'L''introduction à la manchette est une étape cruciale dans le développement du mordant. Elle permet au chien d''associer la manchette à un jeu sûr et contrôlé. Cet exercice aide à construire la confiance et à encourager une prise ferme et confiante.', NULL, NULL, 'Introduction manchette', 'Prise sur manchette tenue', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement la manchette, mordille de manière contrôlée, et lâche sur commande. Il montre confiance et enthousiasme.', 'Le chien montre des signes de peur, d''agressivité, de fatigue excessive, ou d''une perte d''intérêt marquée. Arrêtez si le chien mordille le bras ou la main du handler.', 'Observer l''intérêt du chien pour la manchette, sa volonté d''engager le mordillement, et sa réactivité aux commandes vocales.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/manchette-intro.png'),
('cage-positive', 'Cette méthode vise à rendre la cage un endroit positif et sécurisant pour votre chien, au lieu d''une punition. L''objectif est qu''il y entre volontairement et s''y sente à l''aise, même lorsque la porte est fermée. Une introduction progressive et remplie de renforcements positifs est la clé du succès.', NULL, NULL, 'Introduction positive à la cag', 'Associer la cage au confort', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche de lui-même à aller dans sa cage pour se reposer ou jouer avec un jouet que vous y avez placé. Il y reste calmement pendant au moins 15-20 minutes avec la porte fermée, même lorsque vous n''êtes pas dans la même pièce.', 'Le chien montre des signes marqués de stress, d''anxiété ou de panique (halètement excessif, tremblements, tentatives désespérées de sortie, vocalises persistantes et aiguës) dès l''approche de la cage ou lorsque la porte est fermée. Si le comportement devient agressif, arrêtez immédiatement.', 'Le chien entre volontairement et sans hésitation dans la cage à la commande ''Cage'' ou ''Niche'', pour attraper une friandise ou chercher un jouet. La porte peut être fermée pendant qu''il est à l''intérieur sans qu''il ne montre de signes de détresse.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cage-positive.png'),
('jeu-appropriate', 'Le jeu approprié est essentiel pour le bien-être physique et mental de votre chien. Il permet de renforcer le lien entre vous et votre animal tout en apprenant les règles du jeu. Un jeu bien structuré aide à canaliser l''énergie de votre chien et à prévenir les comportements indésirables.', NULL, NULL, 'Jeu approprié', 'Jouer correctement avec les jouets', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien lâche le jouet volontairement sur commande ''Lâche'', participe activement et de manière contrôlée au jeu, et ne montre pas de signes d''agressivité ou de possessivité excessive. Le jeu se termine dans le calme.', 'Le chien montre des signes de stress, de peur, d''agressivité ou de fatigue excessive. Le propriétaire perd le contrôle de la situation ou se sent inconfortable. Le jeu devient destructeur ou non sécuritaire.', 'Observer l''interaction entre le propriétaire et le chien pendant le jeu. Vérifier la compréhension des commandes ''Lâche'' et l''absence de morsures sur les mains.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jeu-appropriate.png'),
('jeu-calme-senior', 'Enseigne à votre chien à se calmer et à se détendre sur commande, réduisant ainsi l''excitation excessive et favorisant l''auto-contrôle. Cet exercice est idéal pour les moments où votre chien est surexcité ou anxieux. Il établit une base de calme qui peut être étendue à d''autres situations.', NULL, NULL, 'Jeu calme', 'Jeu de manipulation sans effort', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien se calme volontairement et de manière durable (au moins 15 secondes) sur commande ''Calme'', et reste calmement sur son tapis ou dans son panier lorsqu''il y est dirigé.', 'Le chien montre des signes de détresse, de frustration accrue ou d''anxiété. Si l''exercice est devenu une source de stress plutôt que de détente pour le chien, il faut arrêter et revenir à une étape plus simple ou faire une pause.', 'Observer la réponse du chien à la commande ''Calme''. La récompense est donnée dès qu''une baisse significative de l''excitation est constatée (soupir, yeux qui se ferment légèrement, corps qui se détend).)', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jeu-calme-senior.png'),
('boite-a-chaussures', 'Le jeu de boîtes est un exercice stimulant qui encourage la résolution de problèmes et la curiosité chez votre chien. Il consiste à cacher des friandises dans des boîtes de différentes tailles et formes, que le chien doit ouvrir pour les trouver. Cet exercice est excellent pour l''enrichissement mental et peut être adapté à tous les niveaux d''intelligence canine.', NULL, NULL, 'Jeu de boîtes', 'Trouver la bonne boîte parmi plusieurs', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien ouvre de manière autonome les boîtes pour récupérer les friandises, en faisant preuve d''initiative et de persévérance. Il termine l''exercice avec enthousiasme.', 'Le chien montre des signes de stress, de frustration excessive, ou une perte totale d''intérêt. Si le chien essaie de manger des morceaux de carton ou d''autres matériaux non comestibles.', 'Observer le chien interagir avec les boîtes et réussir à trouver la friandise en utilisant ses pattes et son museau de manière appropriée. Le chien doit montrer de l''engagement et de la détermination.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/boite-a-chaussures.png'),
('flair-senior', 'Le jeu de flair doux est une activité de pistage ludique conçue pour stimuler mentalement votre chien et renforcer votre lien. Il s''agit de cacher des friandises ou son jouet préféré dans un endroit facile d''accès pour qu''il puisse les trouver en utilisant son flair. Cet exercice est parfait pour les jours de pluie ou lorsque votre chien a besoin d''une dépense mentale adaptée à son énergie.', NULL, NULL, 'Jeu de flair doux', 'Recherche olfactive sans effort physique', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement et avec plaisir, utilise son flair pour trouver la friandise dans les 30 secondes suivant la commande dans la majorité des cas, et montre une amélioration dans la recherche au fil des séances.', 'Le chien perd tout intérêt, montre des signes de frustration ou de fatigue excessive. Arrêter avant que l''exercice ne devienne une corvée pour lui. Si la frustration est trop grande, arrêter et proposer une activité plus simple.', 'Observer le chien se concentrer sur sa recherche, utiliser son flair pour localiser la friandise, la trouver et la déguster avec satisfaction. Assurer une progression constante dans la difficulté des cachettes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/flair-senior.png'),
('jeu-gobelet', 'Le jeu du gobelet est un excellent exercice pour développer la concentration et la patience de votre chien. Il l''encourage à réfléchir et à résoudre des problèmes pour obtenir sa récompense. C''est une activité ludique qui renforce votre lien et sa confiance en soi.', NULL, NULL, 'Jeu du gobelet', 'Shell game avec gobelets', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien parvient à identifier le gobelet contenant la friandise dans 80% des cas, y compris lorsque vous ajoutez un ou deux gobelets et effectuez quelques mouvements de mélange discrets. Il montre de l''intérêt et de la satisfaction à jouer.', 'Arrêtez la séance si le chien montre des signes de fatigue, de frustration importante ou de déconcentration totale. Il vaut mieux finir sur une note positive avec une réussite facile que de le pousser à l''échec.', 'Après chaque session, assurez-vous que le chien a bien compris où se trouve la friandise avant de passer à l''étape suivante ou de complexifier le jeu. Observez sa concentration et son enthousiasme.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jeu-gobelet.png'),
('muffin-tin-game', 'Le jeu du moule à muffins est un excellent exercice de réflexion et d''olfaction pour les chiens. Il consiste à cacher des friandises dans des compartiments d''un moule et à laisser le chien les découvrir. Cet exercice stimule mentalement votre chien et l''aide à développer ses capacités de résolution de problèmes.', NULL, NULL, 'Jeu du moule à muffins', 'Soulever les balles pour trouver les friandises', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche le moule avec enthousiasme et réussit à trouver au moins 80% des friandises cachées sans montrer de frustration excessive.', 'Le chien perd complètement intérêt, montre des signes de stress ou de frustration intenses, ou devient destructeur envers le matériel.', 'Observer si le chien cherche activement le moule et s''il parvient à extraire la majorité des friandises.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/muffin-tin-game.png'),
('jeux-inter-chiens', 'Le jeu entre chiens est une activité essentielle pour le bien-être physique et mental de votre compagnon. Il permet de canaliser son énergie, d''améliorer sa socialisation et de renforcer ses instincts naturels. Une supervision attentive est cruciale pour garantir la sécurité et le plaisir de tous les participants.', NULL, NULL, 'Jeu entre chiens', 'Sessions de jeu contrôlées', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Les deux chiens participent activement et joyeusement au jeu. Les interactions sont réciproques, sans contrainte ni signes de stress excessif. La séance se termine dans le calme, avec des chiens légèrement fatigués mais heureux.', 'Un des chiens montre des signes clairs de peur, d''inconfort, ou d''agression. Le jeu devient incontrôlable et dangereux. Un des chiens essaie de fuir constamment ou se cache.', 'Observer l''ensemble des interactions entre les chiens. Repérer les signes de jeu positif et réciproque. Identifier les moments de pause ou de retournement pour s''assurer que le jeu est équilibré.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jeux-inter-chiens.png'),
('jeu-interruptible', 'Le ''Jeu Interruptible'' est un excellent exercice pour renforcer le contrôle de soi de votre chien et sa capacité à revenir à vous même lorsqu''il est distrait par un jeu excitant. Cet exercice enseigne au chien que le retour vers le propriétaire est plus gratifiant que de continuer le jeu, ce qui est bénéfique pour la sécurité et la réactivité.', NULL, NULL, 'Jeu interruptible', 'Jouer puis stopper sur commande', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien abandonne volontairement le jeu pour se concentrer sur le rappel et la récompense fournie par le propriétaire dès la première commande, démontrant un contrôle de soi élevé et une forte envie de coopérer.', 'Arrêtez l''exercice si le chien montre des signes de stress excessif, de frustration, d''agressivité ou s''il devient complètement désintéressé par le jeu ou le rappel. Si le chien est dépassé par les distractions ou semble mal à l''aise. L''exercice doit rester amusant et positif pour le chien.', 'L''exercice est validé lorsque le chien interrompt le jeu dès qu''il est invité à le faire, se tourne vers le propriétaire et répond à l''appel avec enthousiasme pour recevoir une récompense. Ce comportement doit être répétitif et fiable dans diverses conditions de jeu.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jeu-interruptible.png'),
('jeu-aquatique', 'Les jeux aquatiques sont une excellente façon de rafraîchir votre chien pendant les journées chaudes et de renforcer votre lien. Cela permet également de dépenser son énergie physique et mentale tout en lui apprenant à aimer l''eau. Assurez-vous que le chien est à l''aise et introduisez-le progressivement pour une expérience positive.', NULL, NULL, 'Jeux aquatiques', 'Activités ludiques dans l''eau', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien participe activement et joyeusement à au moins 75% des jeux aquatiques proposés, qu''il soit à l''aise dans l''eau et qu''il revienne volontairement vers le maître lorsqu''il est appelé pendant la session. La séance se termine dans la joie et la détente pour le chien.', 'Le chien montre des signes de fatigue excessive (halètement prolongé, refus de bouger), de peur, de stress ou d''anxiété. S''il tente de fuir la situation de manière répétée ou manifeste une agressivité envers le jouet ou le maître. Si des conditions météorologiques dangereuses apparaissent (orage, vent fort).', 'Observer le chien montrer des signes d''enthousiasme et de plaisir dans l''eau, s''engager activement dans les jeux proposés et ramener des objets si le jeu l''inclut. Le chien doit rester à l''aise et ne pas montrer de signes de stress ou de peur.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/jeu-aquatique.png'),
('pattern-games', 'Les jeux de patterns sont une méthode d''éducation canine positive qui utilise la répétition de séquences d''actions pour enseigner de nouveaux comportements ou renforcer des apprentissages existants. Ils stimulent mentalement le chien tout en renforçant la relation entre le chien et son propriétaire. Ces jeux ludiques sont parfaits pour développer la concentration, la mémoire et la résolution de problèmes chez votre compagnon.', NULL, NULL, 'Jeux de patterns', 'Séquences prévisibles pour rassurer', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute 3 différents patterns de 3 à 5 étapes chacun avec une précision de 80% et les mélange avec une précision de 70% lors des sessions d''entraînement.', 'Le chien montre des signes de stress, de fatigue excessive, de frustration ou de détresse. Si l''exercice devient une corvée au lieu d''un jeu agréable.', 'Observer si le chien exécute les patterns demandés dans l''ordre correct, avec ou sans aide visuelle légère, et s''il propose des comportements dans les bonnes séquences lors du mélange.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pattern-games.png'),
('joie-moderee', 'Cet exercice vise à enseigner à votre chien une joie modérée et appropriée lors de votre retour à la maison, remplaçant les salutations trop exubérantes. Il encourage un comportement calme et attend la permission pour interagir. Cela renforce votre leadership et établit des attentes claires pour votre chien.', NULL, NULL, 'Joie modérée au retour', 'Accueillir le maître sans débordement', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accueille votre retour avec une excitation modérée, se maintient assis ou calme, et attend que vous donniez la permission d''interagir, sans sauter ou aboyer excessivement.', 'Le chien montre une tendance à la relaxation et à la patience lors de vos retours, et les salutations exubérantes ont significativement diminué ou disparu.', 'Chaque fois que vous rentrez à la maison, appliquez les étapes de préparation, d''entrée silencieuse, et n''accordez de l''attention que lorsque le chien est calme et se tient assis.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/joie-moderee.png'),
('kong-occupe', 'Le Kong d''occupation calme est un jouet distributeur de nourriture qui aide à calmer et à occuper votre chien, particulièrement utile pour les moments de solitude ou de besoin de concentration. En le remplissant avec des aliments appétissants et faciles à extraire, vous offrez à votre chien une activité mentale stimulante qui réduit le stress et l''ennui. Cet exercice favorise l''autonomie et la patience chez le chien, tout en prévenant les comportements destructeurs liés à l''anxiété.', NULL, NULL, 'Kong/occupation calme', 'Utiliser un jouet d''occupation', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien est calme, concentré sur le Kong, et y passe un temps significatif (15 minutes minimum), sans signes de stress ou de frustration. Il finit par le vider ou s''en désintéresser naturellement.', 'Le chien montre des signes de frustration excessive, d''agressivité envers le Kong ou retourne à des comportements indésirables (anxiété, destruction) malgré l''exercice. Le Kong est détruit et représente un danger.', 'Observer la réaction du chien à la présentation du Kong, son niveau d''engagement et de concentration pendant qu''il mange, ainsi que sa satisfaction à la fin.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/kong-occupe.jpg'),
('lacher-commande', 'L''exercice ''lâcher sur commande'' enseigne à votre chien à relâcher volontairement un objet qu''il tient en gueule lorsqu''on le lui demande. C''est une étape cruciale pour de nombreux jeux de rapport et pour assurer la sécurité de votre chien et des autres. Une bonne maîtrise de cet ordre renforce la confiance et la communication entre vous et votre animal.', NULL, NULL, 'Lâcher sur commande', 'Relâcher la prise immédiatement', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien lâche l''objet dès la commande ''Donne'' dans 90% des essais, sans besoin de tirer sur la gueule ou de contrainte. Le lâcher doit être rapide et volontaire.', 'Le chien montre des signes de stress, de frustration ou d''agressivité. Le chien avale l''objet. Le chien refuse systématiquement de coopérer malgré plusieurs tentatives.', 'Demander ''Donne'' à votre chien lorsqu''il tient un objet. Observez s''il lâche l''objet volontairement et sans hésitation après la commande. Récompensez immédiatement le bon comportement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/lacher-commande.png'),
('laisse-ca', 'Ce guide vous aidera à apprendre à votre chien à ignorer les objets tentants sur commande. Cet exercice est essentiel pour renforcer le contrôle de soi chez le chien et prévenir les comportements indésirables comme l''ingestion d''objets inappropriés. Une application cohérente et positive rendra cet apprentissage efficace et agréable pour votre compagnon.', NULL, NULL, 'Laisse ça', 'Renoncer à un objet ou nourriture au sol', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore systématiquement les objets désignés sur commande verbale dans divers environnements, avec ou sans distractions légères, et attend la permission avant d''interagir avec l''objet.', 'Le chien montre des signes de stress, de frustration, d''épuisement, ou si vous n''observez aucun progrès après plusieurs sessions cohérentes, il est temps de faire une pause ou de consulter un professionnel.', 'Commencez dans un environnement calme et sans distraction. Présentez un objet, demandez "Laisse ça". Si le chien ignore l''objet pendant 5 secondes et détourne son attention ailleurs, récompensez. Répétez 5 fois.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/04007630-a229-467b-b517-239fde5f76e3.png'),
('lat-look-at-that', 'Le LAT (Look At That) est une technique de désensibilisation et de contre-conditionnement pour aider votre chien à rester calme face à des déclencheurs comme d''autres chiens, des personnes ou des objets. L''objectif est de changer l''association émotionnelle négative de votre chien en une association positive et neutre. Cela se fait en récompensant votre chien pour avoir simplement regardé le déclencheur, plutôt que de réagir négativement.', NULL, NULL, 'LAT (Look At That)', 'Regarder le déclencheur et se retourner', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien regarde le déclencheur de manière détendue, puis cherche son propriétaire pour une récompense, sans aucune vocalisation, tension corporelle ou tentative d''approche/fuite. Le chien associe le déclencheur à quelque chose de positif (la récompense).', 'Le chien montre des signes de stress (léchage excessif des babines, bâillements, corps raide, oreilles en arrière, queue basse, grondements, aboiements). Si le chien réagit de manière incontrôlable, la séance doit être immédiatement terminée en augmentant la distance ou en arrêtant l''exercice pour la journée.', 'Observer la fréquence et la durée pendant lesquelles le chien regarde le déclencheur sans aucune signe de stress, puis se tourne vers le propriétaire pour la récompense. Le chien devrait montrer une attitude d''anticipation positive plutôt que de peur ou d''agression.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/lat-look-at-that.png'),
('tapis-lickimat', 'Le tapis de léchage est un outil formidable pour canaliser l''énergie de votre chien, réduire son stress et stimuler son intellect. Il consiste à étaler une pâte palatable ou des croquettes sur un tapis texturé, encourageant le chien à lécher pour obtenir sa nourriture. Cet exercice simple mais efficace offre une occupation mentale durable et peut aider à prévenir l''ennui et les comportements destructeurs.', NULL, NULL, 'LickiMat/Tapis de léchage', 'Léchage apaisant sur tapis', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien mange tout le contenu du tapis en léchant de manière continue pendant au moins 5 à 10 minutes, sans montrer de signes de frustration ou d''agression envers l''outil.', 'Le chien perd tout intérêt, commence à mâcher le tapis, montre des signes marqués de frustration, ou si vous avez atteint la durée d''exercice prévue.', 'Observer si le chien est engagé dans l''activité de lécher le tapis et s''il semble calme et concentré. Vérifier qu''il ne cherche pas à mâcher l''outil.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/tapis-lickimat.jpg'),
('lift', 'Le ''Lift'' est un exercice fondamental pour enseigner au chien à initier un mouvement depuis l''immobilité. Il est la base pour de nombreuses autres commandes comme le ''Marche''. L''objectif est que le chien anticipe et déclenche l''action de bouger dès que le signal lui est donné. Cet exercice requiert patience et cohérence pour construire une bonne communication entre le maître et le chien.', NULL, NULL, 'Lift (mise en mouvement)', 'Faire démarrer le troupeau', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien initie le mouvement dès le signal verbal, avec une attitude positive et une légère avance sur le maître, sans attendre d''autre indication.', 'Le chien montre une peur évidente, une forte aversion au signal, ou s''il ne parvient pas à initier le mouvement après plusieurs tentatives clarifiées et motivées.', 'Le chien doit montrer une réaction immédiate et volontaire au signal verbal et au léger coup de laisse, en initiant le mouvement vers l''avant. La récompense est donnée pour l''action de bouger, pas pour rester immobile.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/lift.jpg'),
('limites-maison', 'Cet exercice vise à apprendre au chien où il est autorisé et où il ne l''est pas dans la maison. Il est crucial pour établir des règles claires et une cohabitation harmonieuse. L''objectif est que le chien comprenne les ''zones interdites'' sans stress ni punition excessive.', NULL, NULL, 'Limites dans la maison', 'Apprendre les zones interdites', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Le chien s''éloigne volontairement des zones interdites à la première indication verbale ou gestuelle, ou ne tente même pas de s''en approcher. Il accepte de rester dans les zones autorisées sans chercher à s''échapper.', 'Le chien montre des signes de stress, de peur, d''agressivité ou de détresse. Le chien devient obsédé par les zones interdites ou recherche activement à y aller malgré les avertissements.', 'Observer le comportement du chien en l''absence de supervision permanente et sa réaction à l''approche des zones interdites sans encouragement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/limites-maison.jpg'),
('look-back', 'Cet exercice aide votre chien à se concentrer sur vous et à se détourner des distractions. C''est une compétence fondamentale pour le contrôle des impulsions, utilisable dans différents environnements. Pratiquer le ''Look back'' renforce votre lien et votre communication.', NULL, NULL, 'Look back', 'Renvoyer le chien chercher des animaux manquants', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien établit un contact visuel fiable avec le maître au signal, même en présence de distractions légères, et le maintient pendant au moins 2 secondes.', 'Le chien montre des signes de stress, de frustration ou d''inconfort (léchage de babines, bâillements, évitement). Si le chien ne répond pas ou que la séance est trop longue.', 'Practice the ''Look back'' cue in various environments with increasing distractions. Ensure the dog can reliably make eye contact on cue within 3 seconds, without needing to be lured.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/look-back.png'),
('handling-chiot', 'Cet exercice vise à habituer progressivement votre chiot à être touché et manipulé, ce qui est essentiel pour les futurs examens vétérinaires, les toilettages et les soins généraux. L''objectif est de créer des associations positives avec le toucher, en commençant par des caresses douces et en progressant vers des manipulations plus spécifiques. Une manipulation positive dès le plus jeune âge pose les bases d''un chien confiant et coopératif tout au long de sa vie.', NULL, NULL, 'Manipulation du chiot', 'Habituer aux touchers de tout le corps', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chiot se laisse manipuler sur différentes parties du corps (pattes, oreilles, gueule) pendant au moins 5-10 secondes sans signe de détresse, acceptant les caresses et les récompenses. Il anticipe même positivement le toucher.', 'Le chiot montre des signes évidents de stress : tentatives de fuite répétées, grognements, mordillements, halètements excessifs, ou un corps figé et tendu. L''exercice doit être arrêté si le chiot est visiblement effrayé ou mal à l''aise.', 'Observer la réaction du chiot : s''il reste calme, accepte le toucher sans tenter de fuir ou de mordre, et accepte les récompenses, la manipulation est bien tolérée. Les signes de relaxation (corps souple, queue battante doucement) sont de bons indicateurs.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/handling-chiot.jpg'),
('manipulations-douces', 'Cet exercice enseigne à votre chien à rester calme et confiant lorsque des personnes inconnues l''approchent et le touchent. Il est crucial pour la socialisation et pour prévenir les réactions de peur ou d''agression. Une bonne gestion permet de créer une expérience positive pour le chien.', NULL, NULL, 'Manipulations par des inconnus', 'Accepter d''être touché par des étrangers', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte calmement les approches et les touchers de plusieurs personnes inconnues dans différents environnements sans signe de peur ou d''agression, et montre un comportement général de curiosité ou d''indifférence plutôt que d''anxiété.', 'Le chien montre des signes continus de détresse, d''anxiété, de peur ou d''agression despite les ajustements et les réductions de l''intensité. Si le chien semble dépassé et qu''il n''y a pas d''amélioration après plusieurs réprses.', 'Observer attentivement le langage corporel du chien à chaque étape, en s''assurant qu''il reste détendu et confiant. Demander à l''inconnu de décrire le comportement du chien.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/manipulations-douces.png'),
('mantrailing', 'Le mantrailing est une discipline canine fascinante qui permet à votre chien de suivre une piste olfactive spécifique pour retrouver une personne. C''est un excellent moyen d''exercer son flair et de renforcer votre complicité, tout en lui offrant une activité stimulante mentalement et physiquement. L''initiation consiste à familiariser votre chien avec le processus de recherche dans un environnement contrôlé et simple.', NULL, NULL, 'Mantrailing initiation', 'Suivre la piste d''une personne spécifique', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien suit la piste imprégnée de manière autonome, trouve la personne cachée, et demande sa récompense, indiquant ainsi qu''il a accompli sa mission avec succès.', 'Le chien montre des signes de stress, de fatigue excessive, ou de désintérêt total malgré les encouragements et les simplifications. Une session trop longue ou trop difficile peut être contre-productive.', 'Commencer dans un environnement très simple avec peu de distractions et une piste courte (10-20 mètres). La personne cachée doit rester immobile et facilement trouvable. Augmenter progressivement la complexité (distances, virages, distractions) sur plusieurs séances.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/mantrailing.jpg'),
('marche-sniffari', 'La marche « sniffari » est une promenade où le chien est autorisé à explorer son environnement en utilisant son flair, s''arrêtant et reniflant à sa guise. Cet exercice stimule mentalement votre chien, lui permettant de découvrir le monde à travers ses sens olfactifs, le rendant ainsi plus calme et plus confiant. C''est une excellente alternative aux promenades structurées pour offrir une dépense mentale et réduire le stress chez le chien.', NULL, NULL, 'Marche « sniffari »', 'Marche libre au flair pour décompresser', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien explore activement son environnement en reniflant de manière autonome pendant la majeure partie de la promenade. Il n''y a pas de signes de stress ou d''anxiété manifeste, et il semble réceptif et engagé dans la découverte.', 'Le chien montre des signes de peur, d''agressivité, de stress excessif (halètement intense non lié à l''effort, bâillements répétés, léchage excessif des babines) ou s''il cherche activement à s''isoler et à fuir. Si le chien est épuisé mentalement ou physiquement.', 'Observer si le chien montre des signes d''intérêt pour les odeurs, s''il prend des initiatives d''exploration et s''il semble détendu et moins réactif aux stimuli extérieurs pendant et après la promenade.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-sniffari.png'),
('marche-arriere', 'La marche arrière est un exercice fondamental pour renforcer la communication et la confiance entre le chien et son propriétaire. Il enseigne au chien à reculer sur commande, ce qui est utile dans diverses situations, comme pour sortir d''un encombrement ou pour des exercices d''obéissance plus avancés. Cet exercice demande de la patience et de la clarté dans les signaux pour que le chien comprenne bien ce qui est attendu de lui.', NULL, NULL, 'Marche arrière', 'Reculer en ligne droite', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien recule instantanément et de manière fluide sur commande, de manière répétée et dans différents environnements, tout en gardant le contact visuel avec le propriétaire.', 'Arrêtez l''exercice si le chien montre des signes de stress, de fatigue excessive, d''agressivité, ou si la frustration devient trop importante chez l''un ou l''autre. Reprenez plus tard avec une approche plus douce.', 'Le chien doit reculer sur commande vocale et gestuelle sur une distance de 5 pas sans hésitation majeure ni déplacement latéral excessif.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-arriere.jpg'),
('marche-arriere-sport', 'La marche arrière sportive est un excellent exercice pour renforcer le lien avec votre chien, améliorer sa proprioception et sa confiance. Elle sollicite des muscles différents de la marche en avant et peut aider à corriger certains déséquilibres. Cet exercice demande de la patience et une communication claire entre vous et votre chien.', NULL, NULL, 'Marche arrière sportive (10 pa', 'Reculer 10 pas en ligne droite', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien effectue les 10 pas arrière demandés sans hésitation, en maintenant une dynamique corporelle stable et sans perdre la connexion visuelle avec le handler.', 'Le chien montre des signes de fatigue excessive, de stress, de frustration, ou refuse catégoriquement de continuer l''exercice.Arrêter immédiatement en cas de douleur ou d''inconfort manifeste.', 'Exécuter 10 pas arrière consécutifs de manière fluide et contrôlée, en conservant une bonne posture et en restant attentif aux invites du handler.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-arriere-sport.jpg'),
('marche-au-pied-strict', 'La marche au pied stricte est un exercice fondamental pour établir la communication et le contrôle avec votre chien. Il enseigne au chien à marcher calmement à vos côtés sans tirer, se presser ou s''éloigner. Cet exercice renforce votre leadership et la confiance mutuelle, essentiel pour des promenades sereines.', NULL, NULL, 'Marche au pied stricte', 'Marche collée au pied gauche', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien marche de manière autonome à votre pied, la laisse est détendue, il réagit immédiatement aux changements de direction et de rythme, et reste bien positionné lors des arrêts.', 'Le chien montre des signes de stress (halètement excessif, bâillements, queue basse), de frustration (aboiements, mordillements de la laisse) ou de fatigue. L''exercice est arrêté si le propriétaire n''arrive pas à maintenir la concentration ou le contrôle.', 'Observer si le chien se positionne correctement à votre flanc dès le départ, maintient cette position sans tirer sur la laisse lors des déplacements, des changements de direction et des arrêts.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-au-pied-strict.png'),
('marche-2-chiens', 'Cet exercice enseigne à votre chien à marcher calmement en laisse à vos côtés, même lorsqu''il y a des distractions. Il est essentiel pour des promenades agréables et pour renforcer votre lien avec votre chien. Une bonne gestion de la laisse et de l''environnement est primordiale pour le succès.', NULL, NULL, 'Marche avec 2 chiens', 'Promener deux chiens simultanément', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Les deux chiens marchent à vos côtés, sans tirer, avec des laisses détendues, pendant au moins 5 minutes sans interruption majeure.', 'Si les chiens montrent des signes de stress excessif, d''agressivité, ou si vous ne parvenez pas à maintenir leur attention malgré les ajustements.', 'Plusieurs séances d''entraînement dans différents environnements avec et sans distractions.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-2-chiens.png'),
('marche-relaxation', 'La marche de décompression est une promenade lente et attentive conçue pour permettre au chien de se détendre et de s''orienter sans pression. Elle vise à réduire le stress et à renforcer le lien entre le propriétaire et le chien en se concentrant sur l''environnement et les sensations. C''est un moment privilégié pour observer le comportement naturel de votre chien et lui offrir une pause mentale et physique.', NULL, NULL, 'Marche de décompression', 'Marche lente en pleine nature sans objectif', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien semble visiblement plus calme et détendu à la fin de la promenade qu''au début. La promenade a été vécue comme un moment agréable et sans contrainte pour le chien.', 'Le chien montre des signes de stress répétés (halètements excesifs, bâillements excessifs, léchage des babines, queue basse ou rentrée, tentative de fuite), ou le handler sent que la promenade devient une source de frustration au lieu de détente.', 'Observer la détente physique et mentale du chien : respiration ample, queue et corps détendus, déplacements fluides, intérêt calme pour l''environnement, absence de tension visible ou de signes de stress.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-relaxation.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('marche-marche', 'La marche de marché est un exercice essentiel pour apprendre à votre chien à rester calme et concentré dans un environnement stimulant. Cet exercice simule une promenade dans un lieu fréquenté, comme un marché, où de nombreuses distractions sont présentes. L''objectif est d''éduquer le chien à ignorer ces stimuli et à se focaliser sur son maître, renforçant ainsi leur lien et la confiance mutuelle.', NULL, NULL, 'Marche de marché', 'Évoluer dans un marché bondé', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien marche à vos côtés sans tirer sur la laisse, sans vocalises ni réactions d''agressivité, en ignorant les passants, autres chiens, bruits et odeurs, et en revenant à votre attention lorsque sollicité.', 'Le chien montre des signes de stress excessifs (halètement important, oreilles en arrière, queue basse, tremblements, refus d''avancer), une perte totale de concentration, ou une agressivité envers un stimulus.', 'Observer la capacité du chien à marcher à vos côtés dans divers environnements passants, en maintenant un niveau de stress bas et en ignorant la majorité des stimuli, le tout sur une durée déterminée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-marche.png'),
('marche-douce', 'La marche douce adaptée est une technique d''éducation canine visant à encourager une progression calme et contrôlée en laisse, idéale pour les chiens anxieux ou réactifs. Cet exercice renforce le lien entre le propriétaire et le chien tout en apprenant à ce dernier à se concentrer sur la promenade. Il s''agit d''une méthode positive pour construire la confiance et la coopération mutuelle.', NULL, NULL, 'Marche douce adaptée', 'Promenade lente et confortable', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien marche dans 80% du temps à côté du handler, sans tirer la laisse de manière continue, et réagit calmement aux distractions modérées. La laisse reste majoritairement détendue.', 'Le chien montre des signes de stress excessif (halètements intenses, tremblements, tentatives de fuite), de peur ou d''agressivité. Si l''exercice devient une source de conflit ou d''anxiété pour le chien ou le handler.', 'Effectuer l''exercice sur plusieurs jours, en augmentant progressivement la durée et le niveau des distractions. Observer la réaction du chien lors des transitions (arrêt, démarrage, virages) et sa capacité à maintenir une position non tendue.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-douce.png'),
('marche-eau-peu-profonde', 'Teach your dog to walk calmly in shallow water, building confidence and positive associations. This exercise is great for dogs who are hesitant about water or for rehabilitation purposes. Ensure the water is safe, clean, and has a gentle slope.', NULL, NULL, 'Marche en eau peu profonde', 'Se déplacer dans l''eau jusqu''aux pattes', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'The dog willingly enters shallow water and walks calmly for at least 5 minutes with a loose leash, showing no signs of overt fear or panic, and accepting treats.', 'The dog shows persistent signs of fear (panting, trembling, trying to escape, freezing), is clearly distressed, or the handler feels the situation is unsafe. Also, stop if there are any signs of injury or illness.', 'Observe the dog''s body language for signs of relaxation and positive engagement. Reward all voluntary steps into the water and calm walking movements. Gradually increase duration and distance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-eau-peu-profonde.png'),
('marche-foret', 'La marche en forêt est une excellente activité pour dépenser l''énergie de votre chien tout en stimulant ses sens. Cet exercice permet de renforcer votre lien et d''améliorer son écoute dans un environnement riche en distractions. C''est une opportunité idéale pour pratiquer les commandes de base dans un contexte naturel.', NULL, NULL, 'Marche en forêt', 'Évoluer en milieu naturel riche en odeurs', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'extérieur calme', 'Le chien marche tranquillement en laisse, répond aux commandes de base, ignore la plupart des distractions et semble heureux et détendu pendant la sortie.', 'Le chien montre des signes de fatigue excessive, de stress, de peur ou d''agressivité. La météo devient dangereuse. Le chien s''est blessé.', 'Observer la réactivité du chien aux commandes, son niveau de stress, son intérêt pour l''environnement et sa capacité à rester concentré malgré les distractions.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-foret.png'),
('marche-laisse-longue', 'La marche en longe est un exercice fondamental qui enseigne à votre chien à marcher calmement à vos côtés, sans tirer sur la laisse. Cet exercice renforce le lien entre vous et votre chien tout en lui apprenant l''autocontrôle dans divers environnements. Une bonne marche en longe est la base pour des promenades agréables et sécurisées.', NULL, NULL, 'Marche en longe', 'Marcher avec une longe de 5m', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien marche de manière autonome à gauche ou à droite du propriétaire, avec la longe lâche, en restant attentif aux signaux du handler, et en gérant les distractions courantes sans réaction excessive.', 'Le chien montre des signes de stress excessif (halètement, bâillements répétés, queue basse, évitement), la longe est constamment tendue malgré les arrêts, ou le chien refuse de bouger.', 'L''exercice est validé lorsque le chien peut marcher de manière détendue et sans tirer dans différents environnements pour une durée déterminée (ex: 5 minutes continues) à la voix et sans correction physique constante.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-laisse-longue.png'),
('marche-en-ville', 'La marche en milieu urbain est un exercice essentiel pour habituer votre chien à un environnement potentiellement stressant et riche en stimuli. Elle permet de renforcer votre lien tout en lui apprenant à rester calme et concentré malgré les distractions. Une bonne gestion des sorties améliore grandement le bien-être de votre compagnon et facilite votre quotidien.', NULL, NULL, 'Marche en milieu urbain', 'Évoluer dans un environnement stimulant', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'extérieur contrôlé', 'Le chien marche calmement à côté de son propriétaire, gère les distractions sans réaction excessive, répond aux commandes vocales de base (''Assis'', ''Regarde'') et peut traverser des intersections en toute sécurité. La laisse reste majoritairement détendue.', 'Le chien montre des signes de stress importants (halètement excessif, bâillements répétés, léchage des babines fréquent, tentatives de fuite, agressivité). Le propriétaire n''arrive plus à gérer la situation ou la sécurité n''est plus assurée.', 'Observer la capacité du chien à rester calme et attentif malgré les bruits, les mouvements et les rencontres (autres chiens, personnes, véhicules) tout en marchant à côté de son humain sans tirer sur la laisse. Les réactions doivent être mesurées (curiosité normale, pas d''agressivité ou de peur panique).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-en-ville.png'),
('marche-parc-animalier', 'La marche en parc canin est une excellente façon pour votre chien de socialiser, de dépenser son énergie et de pratiquer son obéissance dans un environnement stimulant. Cet exercice aide à renforcer le lien entre vous et votre chien tout en lui enseignant à réagir de manière appropriée à diverses distractions. Une bonne gestion de la laisse et une communication claire sont essentielles pour que cette expérience soit positive pour tous.', NULL, NULL, 'Marche en parc canin', 'Évoluer dans un parc avec d''autres chiens', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien interagit positivement et calmement avec d''autres chiens, répond aux commandes malgré les distractions, et quitte le parc sans excès d''excitation ou d''anxiété.', 'Signes de stress excessif, d''agression, de peur généralisée chez le chien ou les autres chiens. Si le handler ne se sent plus en contrôle ou en sécurité.', 'Observer le langage corporel du chien et des autres chiens. Vérifier la réaction du chien aux commandes. Noter la fluidité des interactions sociales.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-parc-animalier.png'),
('marche-nocturne', 'La marche nocturne est un excellent exercice pour les chiens qui ont besoin de dépenser de l''énergie supplémentaire en fin de journée, surtout pendant les mois où la lumière du jour est limitée. Elle permet de renforcer le lien entre le propriétaire et le chien tout en assurant une stimulation mentale et physique. Il est crucial d''adapter cette activité au tempérament et à l''endurance de votre chien, en privilégiant la sécurité et le confort de tous.', NULL, NULL, 'Marche nocturne', 'Promenade de nuit avec calme', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien marche calmement à côté du propriétaire avec une laisse détendue la majorité du temps. Le chien montre un intérêt pour l''exploration mais reste attentif au propriétaire. Il n''y a pas de signes de peur ou d''agressivité excessives.', 'Le chien manifeste une peur intense, de l''agressivité, ou une fatigue extrême. Le propriétaire ressent une insécurité ou un manque de contrôle. Des conditions météorologiques dangereuses (pluie torrentielle, tempête, brouillard très dense) rendent la sortie impossible.', 'Observer la posture corporelle du chien : queue basse ou enroulée, oreilles plaquées, grognements ou aboiements excessifs. Noter la réponse du chien aux commandes vocales et aux signaux corporels. Vérifier la tension de la laisse et l''engagement du chien dans l''activité.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-nocturne.png'),
('marche-parallele', 'Cet exercice avancé de marche parallèle enseigne à votre chien à marcher calmement et attentivement à vos côtés, tout en maintenant une distance respectueuse avec un autre chien qui fait la même chose. L''objectif est de développer le contrôle, la concentration et la capacité de votre chien à rester détendu face à la présence d''un congénère, ce qui est essentiel pour une bonne cohabitation et des promenades sereines dans des environnements variés. Nous allons travailler sur la gestion des distractions tout en renforçant le lien entre vous et votre chien.', NULL, NULL, 'Marche parallèle', 'Marcher en parallèle avec un autre chien', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien marche calmement à côté de son maître, en laisse détendue, sans réaction excessive (aboiement, grognement, tiraillement intense) envers l''autre chien, en maintenant une distance appropriée et en étant attentif aux signaux de son maître.', 'Le chien montre des signes de stress importants (halètement excessif, queue basse, oreilles en arrière, tentative de fuite), aboiements ou grognements continus, ou le propriétaire de l''autre chien ne peut plus gérer la situation.', '3 succès consécutifs sur 5 essais à une distance donnée avant de réduire la distance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-parallele.png'),
('marche-sans-tirer', 'La marche sans tirer est un exercice fondamental pour établir une communication claire et une bonne relation avec votre chien en promenade. Il vise à apprendre au chien à marcher à vos côtés sans exercer de tension sur la laisse. Cet exercice renforce la confiance mutuelle et rend les promenades plus agréables pour vous deux.', NULL, NULL, 'Marche sans tirer', 'Marcher à côté sans tension sur la laisse', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien marche à côté du handler avec la laisse toujours détendue, sans tirer, lors de promenades dans des environnements variés et familiers. Le chien regarde le handler pour obtenir des indications ou des récompenses.', 'Il n''y a pas de critère d''arrêt pour cet exercice, il s''agit d''un apprentissage continu pour maintenir de bonnes habitudes de promenade.', 'Observer si le chien maintient une laisse détendue pendant au moins 80% du temps de marche dans un environnement contrôlé (ex: jardin, rue calme). La récompense doit initier un changement de comportement vers la position sans tirer.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-sans-tirer.jpg'),
('marche-sous-pluie', 'La marche sous la pluie est une excellente technique pour aider votre chien à s''habituer à différents environnements et à rester calme même lorsque les conditions ne sont pas idéales. Cet exercice renforce la confiance de votre chien face à des sensations inhabituelles, comme l''eau qui tombe et les bruits de pluie. Une approche progressive et positive est essentielle pour que votre chien associe la pluie à une expérience agréable.', NULL, NULL, 'Marche sous la pluie', 'Accepter les intempéries', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien marche calmement sous une pluie légère à modérée, manifeste de la curiosité pour son environnement et ne montre pas de signes de stress ou de peur importants. Il accepte l''exercice sans appréhension.', 'Le chien montre des signes de peur intense (immobilité totale, tentatives de fuite désespérées, gémissements), de froid excessif (tremblements incontrôlables) ou d''épuisement. L''exercice devient une corvée négative pour le chien.', 'Observe attentivement le langage corporel du chien : recherche de signes de peur (queue entre les jambes, jappements, tremblements, fuite) ou de confort (queue en l''air, queue qui remue, exploration active, demande de jeu).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-sous-pluie.png'),
('trottoir-bordure', 'La marche sur bordure de trottoir est un excellent exercice pour améliorer l''équilibre, la proprioception et la confiance de votre chien. Elle lui apprend à naviguer sur des surfaces irrégulières et légèrement surélevées en toute sécurité. Cet exercice est particulièrement utile pour les chiens sportifs ou ceux qui montrent de l''appréhension face à des terrains variés.', NULL, NULL, 'Marche sur bordure de trottoir', 'Suivre le bord en équilibre', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de marcher sur la bordure d''un trottoir pendant au moins 5 mètres, de manière autonome et détendue, en faisant preuve de confiance et d''équilibre.', 'Le chien montre des signes évidents de peur, d''anxiété, de douleur ou de manque de compréhension. La fatigue excessive du chien ou de l''humain.', 'Observer si le chien monte sur la bordure avec confiance, marche quelques pas (au moins 3) et descend sans hésitation. Vérifier l''absence de signes de stress ou d''inconfort.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/trottoir-bordure.jpg'),
('marche-sur-poutre', 'La marche sur poutre est un excellent exercice pour développer l''équilibre, la confiance et la proprioception de votre chien. C''est un excellent moyen de renforcer votre lien en travaillant ensemble sur un objectif commun. Cet exercice est particulièrement utile pour les chiens nerveux ou manquant de confiance en eux.', NULL, NULL, 'Marche sur poutre', 'Traverser une poutre surélevée', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien parcourt la poutre sur toute sa longueur avec assurance, sans montrer de signes de peur, et descend calmement.', 'Si le chien montre des signes de stress extrêmes (halètement excessif, tremblements incontrôlables, panique) ou s''il refuse catégoriquement de participer malgré les efforts pour le mettre à l''aise.', 'Observer si le chien monte sur la poutre sans hésitation et progresse sur sa longueur avec un minimum de tremblements ou d''anxiété.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-sur-poutre.png'),
('marcher-sans-tirer-chiot', 'Apprendre à un chiot à marcher en laisse sans tirer est fondamental pour des promenades agréables. Cet exercice développe la connexion et la confiance mutuelle entre le chien et son propriétaire. Il est important de commencer tôt pour établir de bonnes habitudes dès le plus jeune âge du chiot.', NULL, NULL, 'Marcher sans tirer (chiot)', 'Premiers pas en laisse sans tension', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chiot marche de manière constante à côté du propriétaire, en maintenant une laisse détendue de façon régulière, même en présence de légères distractions.', 'Le chiot tire de manière incontrôlable, le chiot montre des signes de détresse (halètement excessif, tremblements, tentatives de fuite), ou l''une des parties ne progresse plus malgré la répétition.', 'Observer si le chiot marche à côté du propriétaire avec une laisse détendue pendant au moins 5 mètres consécutifs sans tirer. Récompenser les moments de réussite et s''arrêter si la laisse se tend.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marcher-sans-tirer-chiot.jpg'),
('massage-canin', 'Le massage canin est une excellente méthode pour renforcer le lien avec votre chien, tout en favorisant sa relaxation physique et mentale. Il aide à soulager les tensions musculaires, à améliorer la circulation sanguine et à détecter d''éventuelles douleurs ou zones sensibles. Pratiqué régulièrement, il contribue au bien-être général et à la réduction du stress de votre compagnon.', NULL, NULL, 'Massage canin', 'Masser le chien pour le détendre', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien est calme, détendu, et montre des signes de plaisir (soupirs, corps mou, absence de tension). La séance se déroule sans stress pour le chien et renforce le lien maître-chien.', 'Le chien montre des signes clairs de stress, d''inconfort, de peur ou d''agressivité. Le chien essaie de quitter la zone ou exprime son refus par des grognements ou des tentatives de morsure. Toute douleur évidente détectée chez le chien.', 'Observer attentivement le langage corporel du chien pendant toute la séance : queue basse, oreilles en arrière, bâillements excessifs, léchage des babines, tentatives de fuite sont des signes d''inconfort. Des mouvements de relaxation, un corps mou, des soupirs de bien-être sont des signes positifs.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/massage-canin.png'),
('massage-senior', 'Le massage thérapeutique pour chiens est une technique de relaxation et de bien-être qui peut aider à soulager les tensions musculaires, à améliorer la circulation sanguine et à renforcer le lien entre le propriétaire et son animal. Il est particulièrement bénéfique pour les chiens âgés, ceux qui souffrent d''arthrite ou de blessures, ou simplement pour réduire le stress et l''anxiété. Une approche douce et respectueuse est essentielle pour que le chien associe le massage à une expérience positive.', NULL, NULL, 'Massage thérapeutique', 'Massage pour soulager les douleurs', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien montre des signes clairs de relaxation et de bien-être pendant et après la séance de massage. Il associe le massage à une expérience positive et recherche le contact lors des séances futures.', 'Le chien montre des signes de stress, d''inconfort, d''agitation ou d''agressivité. Si le chien quitte activement la zone de massage ou refuse le contact. En cas de douleur évidente ou de gêne physique.', 'Observer les réactions physiologiques du chien : respiration lente et profonde, relâchement des muscles, bâillements, yeux mi-clos, absence de tension ou de signes de gêne. Le chien recherche activement le contact ou reste calme et détendu.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/massage-senior.png'),
('meditation-chien', 'La méditation avec son chien est une pratique qui vise à renforcer le lien entre le propriétaire et son animal tout en favorisant un état de calme et de relaxation pour les deux. Cet exercice permet de développer la pleine conscience, l''écoute mutuelle et la gestion du stress. En pratiquant régulièrement, vous aiderez votre chien à se sentir plus en sécurité et plus confiant, tout en améliorant votre propre bien-être.', NULL, NULL, 'Méditation avec son chien', 'Session de calme partagée', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le propriétaire et le chien sont capables de maintenir un état de calme et de présence partagée pendant la durée de la séance, sans manifestation de stress ou d''agitation excessive de la part du chien.', 'Le chien montre des signes évidents de stress, d''inconfort, ou d''envie de quitter l''exercice (tentatives répétées de se lever, plaintes, halètements excessifs). Le propriétaire ressent une fatigue ou une frustration intense.', 'Observer la détente physique et mentale du chien (respiration lente, bâillements, soupirs, corps relâché) et la connexion dans le regard entre le chien et le propriétaire.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/meditation-chien.png'),
('mettre-harnais', 'Cet exercice vise à habituer progressivement votre chien au port du harnais, transformant cette étape quotidienne en un moment agréable et sans stress. Une introduction positive est essentielle pour construire une relation de confiance et éviter toute appréhension future. Le but est que le chien associe le harnais à des expériences positives, telles que des friandises et des caresses.', NULL, NULL, 'Mettre le harnais', 'Coopérer pour l''habillage', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien tolère le port du harnais sans montrer de signes d''inconfort ou de stress, accepte de se le faire mettre et retirer sans appréhension. L''association du harnais à des moments positifs est claire.', 'Le chien montre des signes de peur, d''anxiété ou de douleur (grincements, tentatives de fuite, agressivité). Le chien essaie de retirer activement le harnais de manière désespérée. Les tentatives de progression entraînent une augmentation du stress chez le chien.', 'Observer la réaction du chien à chaque étape. Si le chien est détendu, accepte la manipulation et montre de l''intérêt pour les récompenses, l''étape est validée. Si le chien montre des signes de stress (bâillements excessifs, léchage des babines, fuite), l''étape n''est pas encore validée.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/mettre-harnais.png'),
('mini-parcours', 'Le Mini parcours 3 obstacles est un excellent exercice pour développer l''agilité, la confiance et la coordination de votre chien. Il est idéal pour les chiots ou les chiens débutants en agility, car il utilise des obstacles simples et peu intimidants. Cet exercice permet de renforcer le lien entre vous et votre chien tout en lui offrant une activité physique et mentale stimulante.', NULL, NULL, 'Mini parcours 3 obstacles', 'Enchaîner 3 obstacles', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien parcourt les trois obstacles dans l''ordre demandé, de manière autonome ou avec des guidances minimales, avec enthousiasme et sans peur.', 'Le chien montre des signes de stress, de peur extrême, ou une fatigue évidente. L''exercice devient une corvée pour le chien ou le handler. Le chien refuse catégoriquement de participer.', 'Réussir chaque obstacle individuellement plusieurs fois, puis enchaîner les trois obstacles sans hésitation du chien. Le chien doit passer tous les obstacles correctement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/mini-parcours.png'),
('echelle-verticale', 'La montée d''échelle est un excellent exercice pour renforcer la confiance de votre chien, améliorer son équilibre et sa coordination, et développer sa proprioception. Elle est idéale pour les chiens sportifs ou ceux qui ont besoin de gagner en assurance sur différentes surfaces et hauteurs. Cet exercice doit être introduit progressivement et toujours de manière positive.', NULL, NULL, 'Montée d''échelle', 'Grimper une échelle verticale', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien traverse l''échelle à la hauteur définie avec confiance, engageant ses pattes dans chaque espace, plusieurs fois de suite, sans tremblement, refus ou signe de stress.', 'Le chien montre des signes évidents de peur, d''anxiété, de stress, ou refuse catégoriquement de progresser malgré les encouragements et la simplification de l''exercice. Arrêtez si le chien se blesse ou semble avoir mal.', 'Observer le chien traverser l''échelle à la hauteur désirée sans hésitation ni signe de peur, en suivant les indications du handler, puis repasser l''échelle dans l''autre sens.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/echelle-verticale.png'),
('montee-pente', 'La montée de pente est un excellent exercice pour renforcer les muscles de votre chien, améliorer son endurance et sa proprioception. Cet exercice est particulièrement bénéfique pour les chiens actifs, ceux en rééducation physique ou simplement pour varier les activités. Assurez-vous que le terrain est sûr et adapté à la condition physique de votre chien avant de commencer.', NULL, NULL, 'Montée de pente', 'Grimper une pente raide', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien monte et descend la pente choisie avec une bonne posture, un rythme constant et sans hésitation excessive, démontrant confiance et endurance. Il répond aux commandes et reste concentré.', 'Le chien montre des signes de fatigue extrême (halètement excessif, ralentissement marqué, boiterie), de douleur, de peur panique, ou refuse catégoriquement de coopérer malgré les encouragements. Le handler ressent une appréhension ou une perte de contrôle.', 'Observer la posture du chien, sa cadence, sa respiration et sa réaction aux commandes. Vérifier qu''il maintient une bonne connexion avec le handler et qu''il progresse sans signe de stress ou de douleur.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/montee-pente.png'),
('monter-descendre-escaliers', 'Apprendre à votre chien à monter et descendre les escaliers en toute sécurité est essentiel pour son bien-être et sa confiance. Cet exercice progressif permet de construire une relation de confiance tout en développant son équilibre et sa proprioception. Commencez lentement et récompensez chaque petit succès pour rendre l''expérience positive.', NULL, NULL, 'Monter/descendre escaliers', 'Gravir les marches sans tirer', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte et descend l''ensemble de l''escalier avec assurance, de manière contrôlée, en réponse aux commandes vocales ou gestuelles, sans signe de peur ou d''anxiété, et sans aucune hésitation significative.', 'Le chien montre des signes évidents de peur (tremblements, halètement excessif, tentatives de fuite), refuse catégoriquement de coopérer malgré plusieurs tentatives douces, ou manifeste des douleurs physiques lors du mouvement.', 'Observer la réaction du chien lors de la première exposition aux escaliers. V légumes sont les signes de motivation, de confiance et de calme. S''assurer que le chien réagit positivement aux commandes et semble volontaire.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/monter-descendre-escaliers.png'),
('marche-arriere-trick', 'Le Moonwalk est un exercice avancé qui enseigne au chien à reculer de manière contrôlée, en plaçant une patte après l''autre. Cet exercice améliore la proprioception, le contrôle corporel et la confiance du chien. Il est particulièrement utile pour les sports canins tels que l''agility ou le dock diving, mais aussi pour le dressage général.', NULL, NULL, 'Moonwalk', 'Reculer de manière stylée', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien recule de manière fluide et autonome sur une distance de 5 à 10 pas (ou plus selon le niveau) en réponse au signal verbal ''Moonwalk'', avant de recevoir une récompense.', 'Le chien montre des signes de stress, de fatigue, de frustration ou d''anxiété (halètement excessif, bâillements, léchage des babines, tentative de fuite). Le chien refuse catégoriquement de coopérer malgré des tentatives de simplification de l''exercice.', 'Observer si le chien recule de manière contrôlée et coordonnée en réponse au signal verbal (''Moonwalk'') et/ou visuel. Vérifier que le chien maintient une posture relativement droite pendant le mouvement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-arriere-trick.png'),
('mordant-costume', 'Le mordant sur costume complet est une technique avancée de dressage canin qui simule une agression et enseigne au chien à mordre et à tenir fermement un objet protégé. Cet exercice développe l''instinct de prédation, la confiance en soi et le contrôle du chien dans des situations potentiellement stressantes. Il est crucial de pratiquer cet exercice avec un professionnel qualifié pour garantir la sécurité du chien et du manipulateur.', NULL, NULL, 'Mordant sur costume complet', 'Travail en costume intégral', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien saisit fermement l''objet d''attaque sur commande, le maintient pendant le temps imparti avec une pression constante, et le relâche proprement à la commande ''Lâche'' en restant sous contrôle du handler.', 'Arrêtez immédiatement l''exercice si le chien montre des signes de peur excessive, d''agressivité non contrôlée, d''épuisement, ou si le handler perd le contrôle. La sécurité du chien, du figurant et des spectateurs est primordiale.', 'Le mordant sur costume complet doit être validé par un éducateur canin professionnel expérimenté en sports cynophilie ou en travail de protection. La validation inclut l''évaluation de la prise, du contrôle, du lâcher et du comportement général du chien.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/mordant-costume.png'),
('morsure-complete', 'L''exercice de la morsure complète, aussi appelé ''pleine gueule'', vise à habituer votre chien à accepter que sa gueule soit remplie d''objets en toute confiance et sans stress. C''est une étape fondamentale pour la désensibilisation et la gestion de l''excitation lors des mordants ou pour prévenir les ingestions d''objets dangereux. Un chien qui maîtrise cet exercice sera plus à l''aise avec différentes textures et poids dans sa gueule, permettant une meilleure communication et sécurité.', NULL, NULL, 'Morsure complète (pleine gueul', 'Obtenir une prise franche et calme', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien prend l''objet volontairement, le tient calmement en gueule pendant une durée significative (augmentant progressivement), et le relâche sur commande sans hésitation ni stress. L''exercice est généralisé à différents types d''objets sécuritaires.', 'Le chien montre des signes de peur, d''inconfort, de détresse, d''agressivité, ou tente d''avaler l''objet. Si le chien refuse catégoriquement de participer malgré toutes les tentatives de désensibilisation et de renforcement positif.', 'Observer si le chien accepte de prendre et de tenir un objet de taille appropriée en gueule sans signe de peur ou d''agressivité, et s''il le relâche sur commande. L''objet doit rester dans la gueule pendant au moins 5 à 10 secondes avant de progresser.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/morsure-complete.png'),
('motivation-proie', 'La motivation de proie est un exercice fondamental pour canaliser et renforcer le instinct naturel de poursuite du chien de manière contrôlée. Il s''agit d''utiliser un leurre ou un jouet pour simuler une petite proie, incitant le chien à s''engager dans une poursuite sécurisée et excitante. Cet exercice est excellent pour développer l''engagement, la focalisation et le contrôle des impulsions chez le chien, tout en satisfaisant ses besoins comportementaux.', NULL, NULL, 'Motivation de proie', 'Développer l''instinct de proie contrôlé', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien poursuit le jouet avec enthousiasme, engage dans le jeu de traction et lâche le jouet sur commande, en restant concentré sur l''activité.', 'Le chien montre des signes de fatigue excessive, de frustration, d''agressivité ou d''obsession du jouet. L''exercice doit être arrêté immédiatement si le chien devient incontrôlable ou si la sécurité est compromise.', 'Observer si le chien montre de l''intérêt pour le jouet, s''engage dans la poursuite et participe activement au jeu de traction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/motivation-proie.png'),
('detection-multi-odeurs', 'Le jeu "Multi-odeurs" est une excellente activité d''enrichissement olfactif pour votre chien. Il stimule son instinct naturel de recherche en cachant plusieurs odeurs dans des endroits variés. Cet exercice développe sa concentration, sa patience et renforce votre complicité à travers le jeu.', NULL, NULL, 'Multi-odeurs', 'Discriminer plusieurs odeurs cibles', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien trouve la majorité des objets cachés (au moins 75%) dans un temps raisonnable (par exemple, 5 à 10 minutes pour 5 objets) et montre une réelle implication dans la recherche.', 'Le chien montre des signes de fatigue importants, de frustration excessive, ou perd son intérêt pour l''exercice. Si à plusieurs reprises, le chien n''arrive pas à trouver les objets malgré vos aides, il est peut-être temps d''arrêter pour cette session.', 'Le chien doit activement renifler le sol et les environs pour trouver les objets cachés. Il doit montrer de l''intérêt pour les odeurs et, idéalement, marquer les objets trouvés d''une excitation positive (queue qui remue, léger jappement, jeu).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-multi-odeurs.png'),
('musique-forte', 'Cet exercice vise à désensibiliser votre chien aux bruits forts et soudains, comme ceux des feux d''artifice, en utilisant la musique comme couverture. L''objectif est de créer une association positive avec ces sons, afin que votre chien reste calme et détendu même en cas de bruits imprévus. Cette méthode progressive permet de construire la confiance de votre chien et de réduire son anxiété.', NULL, NULL, 'Musique et feux d''artifice', 'Habituation aux sons forts', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, détendu et ne présente pas de signes de peur (pas de halètement excessif, tremblements, etc.) lorsque la musique et les sons de feux d''artifice sont diffusés, même à un volume et une intensité plus élevés.', 'Le chien montre des signes de détresse importants et ne parvient pas à se calmer malgré les ajustements. L''exercice doit être arrêté immédiatement et une approche plus douce doit être envisagée.', 'Observer le comportement du chien pendant et après l''exposition aux sons. Noter les signes de stress ou de relaxation.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/musique-forte.png'),
('nage', 'L''exercice de la nage est une excellente activité physique pour les chiens, offrant un entraînement complet à faible impact. Elle est particulièrement bénéfique pour les chiens souffrant de problèmes articulaires ou en surpoids, ainsi que pour ceux qui aiment l''eau. La nage renforce les muscles, améliore l''endurance cardiovasculaire et procure une stimulation mentale.', NULL, NULL, 'Nage', 'Nager pour la rééducation ou le fitness', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien entre volontairement dans l''eau, nage sur une distance raisonnable sans anxiété excessive, présente des mouvements de nage coordonnés et semble s''amuser ou être détendu pendant l''exercice.', 'Le chien montre des signes évidents de fatigue (halètement excessif, perte de coordination, réticence à continuer), de peur ou de stress. Les signes de froid incluent des tremblements ou une léthargie.', 'Commencez dans une eau calme et peu profonde (lac, étang, piscine pour chiens). Assurez-vous que l''entrée est facile et sans danger. Privilégiez un temps chaud et ensoleillé. Surveillez toujours votre chien attentivement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nage.png'),
('nage-assistee', 'La nage assistée est une technique utilisée pour aider un chien qui n''est pas naturellement à l''aise dans l''eau ou qui a besoin d''un soutien supplémentaire pour nager. Cela se fait généralement à l''aide d''un gilet de sauvetage pour chiens, permettant au propriétaire de guider et de sécuriser l''animal pendant qu''il s''habitue à l''eau. L''objectif est de créer une expérience positive et de renforcer la confiance du chien dans l''eau, tout en assurant sa sécurité.', NULL, NULL, 'Nage assistée', 'Nager avec gilet de sauvetage', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien nage quelques mètres avec un soutien partiel, montre des signes de confiance (queue qui remue, comportement détendu) et semble heureux de participer à l''exercice.', 'Le chien montre des signes de peur ou de stress intenses, est excessivement fatigué, ou le propriétaire décide que la séance doit se terminer pour éviter de créer une aversion à l''eau.', 'Observer la réaction du chien, sa capacité à bouger ses pattes de manière coordonnée sous assistance, et si le chien montre des signes de confiance et de détente dans l''eau.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nage-assistee.png'),
('nage-courant', 'Le ''Nage en courant léger'' est un exercice d''agilité et d''endurance qui simule la nage tout en courant. Il consiste à faire courir votre chien sur une courte période avec un mouvement de pagaie simulé, parfait pour développer sa coordination et sa condition physique. Cet exercice est excellent pour les chiens de toutes races, en particulier ceux qui ont tendance à l''ennui ou qui nécessitent un défoulement supplémentaire.', NULL, NULL, 'Nage en courant léger', 'Nager dans un courant modéré', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute le mouvement de pagaie de manière coordonnée sur une durée minimale d''une minute, en semblant comprendre et apprécier l''exercice.', 'Le chien montre des signes de fatigue excessive, de stress, ou de désintérêt. L''exercice doit être arrêté si le chien semble avoir mal ou s''il est blessé.', 'Observer si le chien imite le mouvement de pagaie avec ses pattes avant pendant la course. Vérifier son engagement et son plaisir pendant l''exercice.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nage-courant.png'),
('nage-longue-distance', 'La nage longue distance est un exercice excellent pour améliorer l''endurance cardiovasculaire de votre chien et renforcer ses muscles. Cela permet également de proposer une activité à faible impact, idéale pour les chiens souffrant de problèmes articulaires ou en convalescence. Assurez-vous que votre chien est à l''aise dans l''eau et commencez progressivement pour éviter la fatigue ou l''anxiété.', NULL, NULL, 'Nage longue distance', 'Nager sur 50m+', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien nage sur une distance raisonnable pour sa condition physique, sans signe de stress, de peur ou de fatigue excessive, et revient de manière fiable à la rive à la demande.', 'Le chien montre des signes évidents de fatigue (haleine haletante excessive, mouvements lents, perte d''intérêt), de détresse ou d''anxiété, ou s''il refuse catégoriquement de continuer.', 'Observer si le chien nage de manière autonome et coordonnée, s''il répond aux commandes vocales de retour, et s''il montre des signes de plaisir et de confiance dans l''eau.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nage-longue-distance.png'),
('pas-toucher-objet', 'Cet exercice vise à apprendre à votre chien à ignorer les objets tentants, qu''il s''agisse de nourriture, de jouets ou d''autres distractions. Il développe l''autocontrôle et renforce votre lien de confiance. La patience et la constance sont les clés du succès pour que votre chien apprenne à vous faire confiance avant de s''intéresser à l''objet.', NULL, NULL, 'Ne pas toucher un objet', 'Ignorer un objet posé au sol', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore volontairement l''objet, même lorsqu''il est à proximité, et revient à votre attention lorsque vous le sollicitez.', 'Le chien montre des signes de stress excessif, de frustration prolongée, ou une incapacité à se concentrer sur vous même avec les meilleures récompenses.', 'Essayer l''exercice dans différents environnements et avec diverses distractions. Progresser vers des objets de plus en plus tentants et des durées d''ignorance plus longues.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pas-toucher-objet.png'),
('nettoyage-oreilles', 'Le nettoyage des oreilles est une étape essentielle pour la santé de votre chien, prévenant ainsi les infections et les irritations. Cet exercice, lorsqu''il est bien réalisé, peut devenir un moment de complicité entre vous et votre animal. Une routine régulière maintient les conduits auditifs propres et sains.', NULL, NULL, 'Nettoyage des oreilles', 'Accepter le produit auriculaire', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme ou gère son stress avec succès pendant la majorité du nettoyage. Les oreilles sont visiblesment plus propres et sans résidus excessifs.', 'Le chien montre des signes de peur intense, d''agressivité (grognements, morsures), ou ressent une douleur évidente. Si une infection est suspectée (odeur, écoulement).', 'Observer attentivement le comportement du chien pendant tout le processus: signes de peur, d''agressivité, de douleur ou de détente. Vérifier visuellement la propreté de l''entrée du canal auditif après le nettoyage.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nettoyage-oreilles.png'),
('nettoyage-yeux', 'Le nettoyage des yeux de votre chien est essentiel pour prévenir les infections et les irritations. Cette routine aide à éliminer les sécrétions, la poussière et les allergènes qui peuvent s''accumuler. Un nettoyage régulier favorise le confort visuel de votre animal et maintient une bonne santé oculaire.', NULL, NULL, 'Nettoyage des yeux', 'Accepter le nettoyage oculaire', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien tolère le nettoyage des yeux sans stress majeur, permet la manipulation de son visage et de ses yeux, et les yeux sont débarrassés des sécrétions et impuretés les plus visibles, sans causer d''irritation.', 'Le chien montre des signes de douleur sévère, de panique, ou cherche activement à fuir. L''intervention doit être arrêtée si des saignements apparaissent ou si l''état de l''œil semble s''aggraver.', 'Observer la réaction du chien : est-il détendu ou stressé ? Le nettoyage est-il effectué sans douleur ni résistance excessive ? Les yeux sont-ils visiblement plus propres après l''intervention ?', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nettoyage-yeux.png'),
('neutralisation-menace', 'Cet exercice vise à apprendre au chien à ignorer les distractions ou les ''menaces'' simulées, réduisant ainsi son anxiété et sa réactivité. Il est crucial pour bâtir la confiance du chien en son propriétaire et pour lui enseigner l''autocontrôle dans des situations potentiellement stressantes. Une approche positive et progressive est essentielle pour le succès.', NULL, NULL, 'Neutralisation de menace', 'Réponse proportionnée à une agression', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien peut ignorer de manière constante un assistant qui s''approche, s''arrête, ou effectue des mouvements discrets, tout en restant calme, en position demandée (assis/couché), et en refusant de poursuivre la ''menace''.', 'Arrêtez immédiatement l''exercice si le chien montre des signes de peur excessive, d''agressivité incontrôlable, ou de stress intense. Ne forcez jamais le chien; si nécessaire, consultez un professionnel du comportement canin.', 'L''exercice est validé lorsque le chien montre une diminution significative de sa réactivité (aboiements, grognements, tension) face à la ''menace'' simulée. Il maintient le contact visuel avec le propriétaire ou se tourne vers lui pour obtenir des instructions ou des récompenses.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/neutralisation-menace.png'),
('nom-jouets', 'Cet exercice vise à apprendre au chien à identifier et rapporter des jouets spécifiques sur commande vocale. En associant un mot à chaque jouet, vous développez sa compréhension du langage et ses capacités cognitives. C''est un excellent jeu pour renforcer votre lien tout en stimulant son intelligence.', NULL, NULL, 'Nommer les jouets', 'Apprendre le nom de différents jouets', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien rapporte le jouet spécifique demandé parmi une sélection de 5 jouets différents, sur commande vocale, sans hésitation et avec enthousiasme.', 'Le chien montre des signes de stress, de fatigue excessive ou de frustration. La séance dépasse 15 minutes. Le chien refuse de participer ou devient apathique.', 'Chaque jouet doit être identifié correctement lorsqu''il est nommé, de manière répétée et sous de légères distractions. Le chien doit rapporter le jouet demandé à au moins 80% du temps sur 10 essais.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nom-jouets.png'),
('nosework-piece', 'Le Nosework est un sport canin qui consiste à apprendre à votre chien à rechercher des odeurs spécifiques. Cette activité stimule mentalement et physiquement votre compagnon, renforçant ainsi votre lien. C''est une excellente manière d''occuper votre chien de façon positive et enrichissante, adaptée à tous les niveaux.', NULL, NULL, 'Nosework dans une pièce', 'Trouver l''odeur cachée dans la pièce', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement l''odeur cible et indique clairement sa présence en atteignant la zone de l''objet caché.', 'Le chien montre des signes de fatigue, de stress, de démotivation, ou quitte la zone de recherche sans indication claire.', 'Validez la recherche en vous assurant que le chien identifie la zone où se trouve l''odeur cible, indépendamment de la facilité de la cachette.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nosework-piece.png'),
('nosework-boites', 'Le Nosework en boîtes est une discipline olfactive passionnante qui permet de stimuler les sens de votre chien et de renforcer votre lien. Il consiste à cacher des odeurs spécifiques dans des contenants variés, obligeant le chien à utiliser son flair pour les retrouver. Cet exercice est idéal pour canaliser l''énergie de votre compagnon et développer sa confiance en lui, tout en s''amusant.', NULL, NULL, 'Nosework en boîtes', 'Identifier l''odeur cible parmi les boîtes', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement, manifeste un intérêt pour l''odeur et signale sa présence de manière fiable (par exemple, en s''asseyant devant la boîte ou en la reniflant intensément). Il doit réussir à trouver l''odeur dans des conditions progressives de difficulté.', 'Si le chien montre des signes de stress, de frustration, de fatigue excessive, ou si l''exercice n''est plus amusant pour lui. Il faut alors arrêter la séance et reprendre plus tard ou simplifier l''exercice.', 'Chaque session doit se terminer par une recherche réussie où le chien identifie l''odeur cible dans au moins une des boîtes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nosework-boites.png'),
('nosework-exterieur', 'Le Nosework en extérieur est une activité ludique qui stimule les sens naturels de votre chien en lui apprenant à rechercher des odeurs spécifiques dans divers environnements extérieurs. Cet exercice renforce votre lien tout en développant sa confiance et sa concentration. C''est une excellente façon d''occuper mentalement votre chien et de lui offrir une dépense saine.', NULL, NULL, 'Nosework en extérieur', 'Recherche olfactive en plein air', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien trouve l''odeur cible de manière autonome dans 80% des recherches proposées, en utilisant son flair et en ignorant les distractions.', 'Arrêtez l''exercice si le chien montre des signes de stress, de fatigue excessive, d''épuisement ou s''il devient frustré ou agressif. Respectez les limites physiques et mentales de votre chien.', 'Validez la recherche lorsque le chien signale clairement la présence de l''odeur cible par une attitude fixe, un mordillement léger ou un autre comportement appris pour indiquer la localisation.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/nosework-exterieur.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('obeissance-en-groupe', 'L''obéissance en groupe enseigne aux chiens à rester concentrés sur leur propriétaire malgré les distractions d''autres chiens. Cet exercice renforce le contrôle et la communication entre le maître et le chien dans un environnement social stimulant. Il est essentiel pour développer un chien bien équilibré et réactif, capable de gérer les situations sociales avec calme et confiance.', NULL, NULL, 'Obéissance en groupe', 'Exécuter des ordres parmi d''autres chiens', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien répond aux commandes de base avec moins de 2 distractions sur 3 pendant la séance, maintient un contact visuel régulier avec son propriétaire et reste calme lorsque les autres chiens travaillent.', 'Le chien montre des signes de stress excessif (bâillements fréquents, halètement excessif, oreilles en arrière, queue basse, tentative de fuite) ou une agressivité envers un autre chien ou propriétaire.', 'Observer si le chien maintient sa position et son attention sur son propriétaire pendant 30 secondes avec un autre chien présent à moins de 5 mètres. Répéter l''exercice avec 3 chiens différents dans le groupe.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/obeissance-en-groupe.png'),
('obeis-en-mouvement', 'L''obéissance en mouvement est un exercice fondamental pour renforcer la connexion entre le chien et son propriétaire tout en travaillant sur la réactivité et le contrôle des impulsions. Cet exercice consiste à maintenir une position ou à exécuter des commandes spécifiques pendant que le chien et le propriétaire se déplacent. Il est essentiel pour améliorer la communication dans des environnements dynamiques et pour préparer le chien à des situations plus complexes.', NULL, NULL, 'Obéissance en mouvement', 'Exécuter des ordres tout en marchant', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste constamment à la position désirée (généralement à gauche) pendant la marche, sans tirer, et répond aux commandes de position sur demande sans hésitation, même en présence de légères distractions.', 'Le chien montre des signes de stress, de peur, d''inconfort, de fatigue excessive, ou si le propriétaire devient frustré. L''exercice doit toujours rester positif pour le chien.', 'Observer la régularité de la position du chien à vos côtés lors des changements de rythme, de direction et lors des demandes de position sans qu''il ne tire ou ne s''arrête. La récompense doit être donnée de manière fluide et fréquente au début.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/obeis-en-mouvement.png'),
('obeissance-rythme-IPO', 'L''obéissance IPO/IGP est une discipline sportive canine exigeante qui teste le lien, la communication et la capacité de travail entre le chien et son maître. Elle se décompose en trois phases : l''obéissance, le pistage et la défense, chacune évaluant des compétences spécifiques. L''objectif est de former un chien équilibré, obéissant et confiant, capable de suivre des instructions précises dans divers environnements. Ce sport met en valeur l''intelligence, la concentration et la volonté de travail du chien, tout en renforçant la complicité avec son handler.', NULL, NULL, 'Obéissance IPO/IGP', 'Routine d''obéissance IGP complète', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Un score total élevé, indiquant une exécution parfaite ou quasi-parfaite de tous les exercices dans les trois phases (obéissance, pistage, défense). Le chien démontre une excellente compréhension des consignes, un engagement total et une grande complicité avec son handler.', 'Les critères d''arrêt incluent une faute éliminatoire (ex: morsure intempestive en défense, refus répété d''obéir), un comportement dangereux ou incontrôlable du chien, ou si le chien montre des signes de stress ou de fatigue extrêmes qui le mettent en danger.', 'L''évaluation se fait par un juge professionnel lors de compétitions officielles, selon les règles strictes de la fédération canine concernée (ex: FCI pour le niveau international). Le chien est jugé sur sa précision, son enthousiasme, sa rapidité d''exécution et sa concentration pendant chaque phase de l''exercice.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/obeissance-rythme-IPO.png'),
('non-verbal', 'L''obéissance non verbale est un exercice avancé qui vise à renforcer la communication silencieuse entre le chien et son maître. Il permet au chien de développer une meilleure concentration et réactivité aux signaux subtils du corps. Cet exercice est idéal pour les chiens ayant déjà une bonne base d''obéissance et pour approfondir le lien de confiance.', NULL, NULL, 'Obéissance non verbale', 'Répondre aux signaux gestuels uniquement', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute correctement les ordres non verbaux à une distance raisonnable (10-15 mètres) et avec des distractions modérées, tout en restant concentré sur son maître.', 'Le chien montre des signes de stress, de fatigue excessive, de peur, d''agressivité ou de désintérêt marqué pour l''exercice. Absence de progrès constants malgré des ajustements.', 'Observer la réactivité et la précision du chien aux signaux non verbaux du maître dans diverses situations environnementales.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/non-verbal.png'),
('obeissance-sous-pression', 'Cet exercice vise à renforcer l''obéissance de votre chien dans des environnements distrayants et potentiellement stressants. Il aide à construire la confiance et la concentration du chien face à l''adversité. L''objectif est que le chien maintienne son calme et réponde aux commandes malgré les stimuli extérieurs.', NULL, NULL, 'Obéissance sous pression', 'Obéir malgré la présence du figurant', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient une position demandée (assis, couché, reste) ou exécute la commande de rappel ou de marche au pied avec succès dans 80% des cas, malgré des distractions modérées à fortes, pendant au moins 30 secondes. Le chien montre des signes de confiance et non de peur.', 'Le chien montre des signes de peur intenses, de stress excessif (halètement incontrôlable, tremblements), d''agressivité, ou s''il échoue systématiquement à répondre aux commandes malgré des ajustements répétés des distractions et des récompenses. Si le chien refuse catégoriquement de participer, il faut arrêter et reprendre à un niveau plus facile.', 'Documenter la fréquence et l''intensité des distractions sous lesquelles le chien répond correctement aux commandes à chaque séance. Noter les réactions physiologiques du chien (queue basse, halètement excessif, etc.).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/obeissance-sous-pression.png'),
('obeis-sous-stress', 'Cet exercice vise à renforcer l''obéissance de votre chien dans des environnements distrayants et potentiellement stressants, simulant des situations opérationnelles. Il s''agit de maintenir la concentration et le contrôle du chien face à des stimuli inattendus. L''objectif est de construire une confiance mutuelle et un lien solide sous pression.', NULL, NULL, 'Obéissance sous stress opérati', 'Exécuter des ordres en situation tendue', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient sa posture et son attention sur le maître ou exécute la commande demandée malgré la présence et l''action de distractions variées, démontrant un niveau de stress contrôlé.', 'Le chien montre des signes clairs de panique, de peur excessive, d''agressivité non contrôlée, ou tente de fuir de manière désespérée. Le maître doit immédiatement mettre fin à la session si le bien-être du chien est compromis.', 'Observer la capacité du chien à maintenir une commande (assis, reste, au pied) pendant au moins 30 secondes face à une distraction active (bruit, mouvement, personne dans le champ de vision). Le chien ne doit pas tenter de fuir, se recroqueviller, ou montrer de signes d''agressivité réactive.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/obeis-sous-stress.png'),
('obeissance-terrain-varie', 'L''exercice ''Obéissance terrain varié'' vise à renforcer l''obéissance de votre chien dans des environnements nouveaux et stimulant. Il est conçu pour tester la concentration de votre chien face aux distractions et pour améliorer sa réponse aux commandes dans diverses situations. Cet exercice est crucial pour développer un chien fiable et à l''écoute dans toutes les circonstances.', NULL, NULL, 'Obéissance terrain varié', 'Obéir sur différentes surfaces et terrains', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien répond aux commandes de base (''assis'', ''reste'', ''couché'', ''viens'') avec une fiabilité d''au moins 80% dans un environnement avec distractions modérées. Le rappel est rapide et volontaire.', 'Le chien montre des signes de stress, de fatigue excessive, de peur, ou d''agressivité. L''éducateur ou le propriétaire ne parvient plus à capter l''attention et la coopération du chien.', 'Observer la réactivité du chien aux commandes verbales et aux gestes, même en présence de distractions variables. Évaluer la qualité de l''exécution (vitesse, précision) et la constance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/obeissance-terrain-varie.png'),
('occupation-seul', 'Cet exercice vise à apprendre à votre chien à rester seul à la maison sans développer d''anxiété de séparation. L''objectif est de lui faire comprendre que votre départ est temporaire et qu''il n''y a pas lieu de s''inquiéter. Une bonne gestion de cet exercice contribue au bien-être de votre chien et à la tranquillité de votre foyer.', NULL, NULL, 'Occupation seul', 'Utiliser un enrichissement en votre absence', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, détendu, ne présente pas de signes de détresse, et ne fait pas de bêtises pendant et après l''absence. Il ne manifeste pas d''excitation excessive au retour.', 'Le chien montre des signes constants de mal-être, d''anxiété intense, de destruction malgré des tentatives répétées d''assouplissement, ou si l''exercice devient contre-productif malgré des adaptations. Dans ce cas, consulter un professionnel.', 'Observer le chien pendant les absences via une caméra ou en restant dans une pièce adjacente sans être vu. Noter les réactions du chien (halètement, vocalises, errance, destruction, malpropreté, etc.).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/occupation-seul.png'),
('outrun', 'L''exercice ''Outrun'' est une technique avancée d''éducation canine où le chien contourne un objet ou une personne, puis revient à sa position initiale ou à côté de son maître. Cet exercice développe l''agilité, la compréhension des consignes et renforce la connexion entre le chien et son propriétaire. Il est idéal pour les chiens ayant déjà acquis les bases de l''obéissance et cherchant à relever de nouveaux défis.', NULL, NULL, 'Outrun (contournement)', 'Contourner le troupeau par la gauche ou droite', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien effectue le contournement de manière fluide, sans hésitation ni distraction, et revient au maître sur commande dans 80% des essais.', 'Le chien montre des signes de stress, de fatigue, de peur ou d''agression. Le chien n''arrive plus à se concentrer malgré les encouragements. La frustration du chien ou du maître est trop importante.', 'Le chien exécute le contournement complet de l''objet sur commande verbale (''Tourne'') puis revient à la position de départ à la commande (''Viens''). Le geste du maître est minimal ou absent.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/outrun.png'),
('ouvrir-porte', 'Apprenez à votre chien à pousser une porte avec son museau pour l''ouvrir. Cet exercice développe l''autonomie de votre chien et peut être utile dans certaines situations. Il nécessite patience et renforcement positif.', NULL, NULL, 'Ouvrir une porte', 'Tirer une corde pour ouvrir', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien ouvre la porte de manière fiable sur commande verbale dans différentes situations et avec différentes portes, sans aide ou leurre du handler.', 'Le chien montre des signes de stress, de peur ou de frustration. L''exercice devient une corvée plutôt qu''un jeu pour le chien. Le chien refuse catégoriquement d''interagir avec la porte.', 'Entraînez le chien à ouvrir une porte fermée (sans verrou), puis une porte légèrement entrouverte, et enfin une porte complètement fermée, en utilisant uniquement le signal verbal ''Ouvre''. Observez si le chien initie l''action pour passer ou pour explorer.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ouvrir-porte.png'),
('palissade', 'La palissade, aussi appelée exercice du mur, est une technique d''éducation canine qui consiste à apprendre au chien à rester immobile le long d''un mur ou d''une surface verticale. Cet exercice développe la concentration, l''obéissance et la gestion de l''espace du chien. Il est particulièrement utile pour les chiens ayant tendance à être trop vifs ou à manquer de self-contrôle.', NULL, NULL, 'Palissade (mur)', 'Escalader et franchir un mur', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient la position couchée le long du mur pendant au moins 5 à 10 minutes sans qu''il soit nécessaire de le corriger, et répond avec enthousiasme à l''ordre de libération.', 'Le chien montre des signes de stress excessif, d''épuisement ou de douleur. Si le chien refuse catégoriquement de coopérer après plusieurs tentatives raisonnables, il faut arrêter l''exercice pour la séance.', 'Observer si le chien reste immobile pendant le temps imparti sans agitation et sans tentative de mouvement, le tout sous contrôle de la laisse. L''ordre de libération doit être exécuté rapidement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/palissade.png'),
('palpation-corporelle', 'La palpation corporelle est une technique essentielle pour que votre chien s''habitue à être manipulé, favorisant ainsi la confiance et facilitant les examens vétérinaires. Cet exercice consiste à toucher doucement votre chien sur tout le corps, en commençant par des zones qu''il apprécie et en progressant vers des zones plus sensibles. Une bonne palpation corporelle permet de détecter précocement d''éventuelles anomalies ou blessures.', NULL, NULL, 'Palpation corporelle', 'Accepter la palpation de tout le corps', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte la palpation de toutes les parties de son corps sans signe de stress, d''anxiété ou de douleur, le tout dans une ambiance détendue et positive.', 'Si le chien montre des signes évidents d''inconfort, de peur, d''agressivité (grognement, tentative de morsure) ou une douleur physique évidente lors de la palpation.', 'Observer la réaction du chien à chaque contact. Le chien doit rester détendu, curieux ou indifférent, et non anxieux ou stressé. Le handler doit pouvoir toucher l''ensemble du corps sans réaction négative.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/palpation-corporelle.png'),
('parcours-complet', 'Le parcours complet est un exercice d''agilité et d''obéissance qui met à l''épreuve la coordination et la communication entre le chien et son propriétaire. Il combine plusieurs obstacles classiques d''agility, tels que des sauts, des tunnels et des slaloms, exigeant une bonne compréhension des commandes et une confiance mutuelle. Cet exercice est idéal pour renforcer le lien, améliorer la forme physique du chien et canaliser son énergie de manière productive.', NULL, NULL, 'Parcours complet', '20+ obstacles en séquence', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit tous les obstacles du parcours dans l''ordre désigné, avec un minimum d''hésitation et une bonne réactivité aux commandes. Le propriétaire gère le parcours de manière fluide et positive.', 'Le chien montre des signes de stress, de peur ou de fatigue excessive. Le propriétaire devient frustré ou perd patience. Un oubli important dans la sécurité du montage du parcours est détecté.', 'Observer la capacité du chien à franchir chaque obstacle individuellement avec correction à chaque étape, puis enchaîner les obstacles avec succès. Vérifier la compréhension des commandes vocales et des signaux corporels associés à chaque obstacle.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/parcours-complet.png'),
('marche-obstacles', 'Le parcours d''obstacles naturels est un excellent moyen de stimuler mentalement et physiquement votre chien en utilisant son environnement. Il encourage la confiance en soi, la résolution de problèmes et renforce votre lien. Cet exercice est adaptable à tous les niveaux, du débutant au plus expérimenté, en utilisant ce que la nature offre.', NULL, NULL, 'Parcours d''obstacles naturels', 'Utiliser l''environnement naturel', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit la majorité des obstacles proposés sans hésitation excessive, en gardant son calme et en montrant une attitude positive et désireuse de continuer.', 'Le chien montre des signes évidents de fatigue, de stress, de peur, ou une perte d''intérêt marquée pour l''exercice, même après plusieurs tentatives de simplification ou de encouragement.', 'Observer si le chien aborde chaque obstacle de manière volontaire, s''il écoute les commandes vocales et s''il termine le parcours avec enthousiasme.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/marche-obstacles.png'),
('detection-parcours', 'Le Parcours de Détection complet est un exercice stimulant qui met à profit le flair naturel de votre chien pour retrouver une odeur spécifique dans un environnement complexe. Il s''agit d''une activité enrichissante qui renforce votre lien et développe la confiance de votre compagnon. Cet exercice est idéal pour les chiens de tous âges et de toutes races, et peut être adapté à différents niveaux de difficulté.', NULL, NULL, 'Parcours de détection complet', 'Enchaîner plusieurs zones de recherche', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien identifie de manière fiable et rapide l''odeur cible dans 80% des recherches, avec une recherche active et un signalement correct et durable.', 'Arrêtez l''exercice si le chien montre des signes évidents de stress, de fatigue extrême, de frustration ou de blessure. Arrêter également si vous avez atteint un niveau de difficulté trop élevé pour le chien à ce stade.', 'L''exercice est validé lorsque le chien est capable de localiser l''odeur cible dans des environnements variés et avec un niveau de difficulté croissant, en utilisant un signalement clair et constant.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-parcours.png'),
('trial-parcours', 'Le parcours de trial est une discipline canine qui évalue l''agilité, la rapidité et la précision d''un chien dans l''exécution de diverses tâches. Il simule des situations de travail ou de jeu qu''un chien et son maître pourraient rencontrer. Cet exercice renforce la complicité et la communication entre le binôme maître-chien.', NULL, NULL, 'Parcours de trial', 'Parcours complet de compétition', 'La constance est la clé du succès', '25 min', '5 fois', '1x/jour', 'tous', 'Le chien franchit tous les obstacles dans l''ordre prescrit, avec fluidité et sans refus, en réagissant aux commandes verbales et gestuelles du maître.', 'Le chien montre des signes de stress, de peur, d''agressivité ou de fatigue extrême. Disqualification en cas de non-respect des règles de sécurité ou de la voie du parcours.', 'Observer la capacité du chien à franchir tous les obstacles du parcours sans hésitation excessive et en suivant les indications du maître. Chronométrer la performance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/trial-parcours.png'),
('parcours-mental', 'Le parcours mental est un excellent exercice pour stimuler l''intellect de votre chien et renforcer votre complicité. Il consiste à créer un parcours avec différents défis olfactifs et cognitifs que le chien doit résoudre. Cet exercice est idéal pour les chiens de tous âges et de toutes races, et peut être adapté à chaque niveau.', NULL, NULL, 'Parcours mental', 'Séquence d''actions à mémoriser', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien termine le parcours avec satisfaction, trouve au moins 80% des friandises, et fait preuve de persévérance face aux défis. Il est évident qu''il apprécie l''exercice.', 'Le chien montre des signes clairs de stress, d''épuisement, de frustration excessive ou de désintérêt. Si le chien devient agité ou détruit des éléments du parcours sans chercher les friandises, arrêtez l''exercice.', 'Le chien explore activement tous les éléments du parcours, manipule les objets et trouve la majorité des friandises cachées sans aide excessive. Le chien montre de l''enthousiasme et de la concentration.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/parcours-mental.png'),
('pas-bouger', 'L''exercice ''Pas bouger'' enseigne à votre chien à rester immobile sur commande. C''est un excellent exercice pour développer l''autocontrôle et la patience chez le chien. Il est fondamental pour la sécurité et la gestion quotidienne du chien, notamment lors de l''ouverture de portes ou dans des situations potentiellement dangereuses.', NULL, NULL, 'Pas bouger', 'Rester immobile malgré les distractions', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien reste immobile sur commande pendant au moins 30 secondes avec des distractions modérées, sans signe de stress, et attend ma libération verbale (''Ok'' ou autre).', 'Le chien montre des signes de stress (bâillements excessifs, lèchements de babines, queue basse, halètement inapproprié), ou il est clairement incapable de comprendre ou de maintenir la commande malgré les ajustements.', 'Observer la réaction du chien à la commande ''Pas bouger'', le temps pendant lequel il reste immobile, et sa capacité à résister aux distractions introduites. Le chien ne doit pas avoir l''air stressé ou confus.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/f25aed6d-53b3-4111-872e-64fb711e53d3.png'),
('passage-en-arc', 'L''exercice du passage en arc de cercle est une excellente façon d''améliorer la connexion entre vous et votre chien tout en travaillant son équilibre et sa proprioception. Il consiste à faire tourner votre chien autour de vous en formant un arc de cercle, lui apprenant ainsi à anticiper vos mouvements et à rester concentré. C''est un exercice ludique qui peut être adapté à tous les niveaux de difficulté.', NULL, NULL, 'Passage en arc de cercle', 'Contourner les déclencheurs en arc', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien tourne en arc de cercle de manière fluide autour du handler sur une distance d''au moins 3 mètres, en maintenant une connexion visuelle et en répondant aux signaux verbaux et corporels sans tirer sur la laisse. Le chien semble engagé et réceptif.', 'Le chien montre des signes de stress, de fatigue, de peur ou de frustration évidents. Il refuse catégoriquement de coopérer malgré plusieurs tentatives. Les distractions externes deviennent trop importantes pour le chien.', 'Observer si le chien suit le handler en cercle sans hésitation significative ou sans tirer sur la laisse. Vérifier la concentration du chien sur le handler malgré les distractions mineures.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/passage-en-arc.png'),
('passer-une-porte', 'L''exercice ''Passer une porte'' vise à enseigner au chien à attendre patiemment et à entrer dans une pièce ou à traverser un seuil sur commande, tout en maintenant son calme. Cet exercice est fondamental pour gérer l''excitation du chien lors des entrées et sorties. Il renforce la confiance et le contrôle de soi du chien, ainsi que la communication entre le chien et son propriétaire.', NULL, NULL, 'Passer une porte', 'Passer les portes calmement en laisse', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien attend calmement à la porte, sans aboyer ni se tortiller, jusqu''à ce qu''il reçoive la commande de passage. Il traverse ensuite la porte en respectant la distance avec le handler et sans se précipiter une fois de l''autre côté.', 'Arrêtez l''exercice lors d''une session si le chien montre des signes de frustration intense, d''épuisement, ou s''il devient agressif. En cas de peur marquée, recentrez-vous sur des exercices plus simples et proposez un environnement rassurant.', 'Pour valider l''exercice, le chien doit systématiquement attendre que la commande de passage soit donnée et franchir la porte dans le calme, en suivant le handler. La durée de l''attente et la rapidité du passage doivent s''améliorer progressivement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/passer-une-porte.png'),
('passerelle', 'L''exercice de la passerelle enseigne au chien à marcher sur des surfaces surélevées de manière calme et confiante. Il est essentiel de construire cette compétence progressivement pour éviter toute peur ou hésitation. Cet exercice améliore l''équilibre et la conscience corporelle du chien, renforçant ainsi sa confiance en lui et votre relation.', NULL, NULL, 'Passerelle', 'Monter et traverser une passerelle', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien monte sur la passerelle de manière autonome, la traverse sans hésitation ni nécessité de correction, et en descend de l''autre côté. Il arbore une attitude détendue et confiante pendant tout le processus.', 'Le chien montre des signes de peur, de stress ou d''inconfort clair (tremblements, halètements excessifs, retrait, refus catégorique de bouger). Tout signe de douleur ou de difficulté physique.', 'L''objectif est que le chien monte sur la passerelle, la traverse calmement et en confiance, puis en descende sans hésitation ni peur. Les récompenses sont utilisées pour encourager le comportement désiré. Le chien doit montrer des signes de confort et de confiance, sans tremblements ni halètements excessifs dus au stress.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/passerelle.png'),
('patrouille-base', 'La patrouille de base est un exercice d''obéissance qui apprend au chien à rester concentré sur son maître malgré les distractions environnantes. Cet exercice renforce le lien entre le chien et son propriétaire, tout en développant l''autocontrôle du chien. Il est essentiel pour de nombreuses activités canines avancées et pour une bonne intégration sociale.', NULL, NULL, 'Patrouille de base', 'Marche de surveillance avec le chien', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien peut marcher sans tirer sur la laisse, en gardant le contact visuel avec son maître, pendant au moins 5 minutes dans un environnement modérément distrayant (autres personnes, chiens calmes à distance visible mais non immédiate).', 'Le chien montre des signes de stress importants (halètement excessif, bâillements répétés, queue basse ou rentrée) ou d''excitation incontrôlable, ou le maître est incapable de maintenir la concentration du chien malgré ses efforts.', 'Observer la capacité du chien à maintenir sa concentration sur le maître et à ignorer les distractions à différents niveaux, tout en marchant calmement en laisse à ses côtés. La distance par rapport aux distractions et la durée de la concentration sont des facteurs clés.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/patrouille-base.png'),
('pattes-avant-surevelees', 'Cet exercice apprend au chien à placer ses pattes avant sur une cible surélevée, comme une petite marche ou un banc bas. Cela renforce le contrôle du corps, la confiance et la proprioception. C''est une excellente base pour des tricks plus complexes et des sports canins.', NULL, NULL, 'Pattes avant surélevées', 'Poser les pattes avant sur un objet', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte et reste sur la cible de manière autonome à 80% des essais, sur commande, sans hésitation ni peur, pour une durée de 5 secondes.', 'Le chien montre des signes de stress, de peur, de fatigue excessive, ou s''il refuse catégoriquement de participer à l''exercice malgré des adaptations.', 'Le chien monte volontairement ses deux pattes avant sur la cible désignée et maintient la position pendant au moins 5 secondes, sur commande verbale et/ou visuelle, sur une hauteur de cible de 10-15 cm.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pattes-avant-surevelees.png'),
('peekaboo', 'Le jeu du ''Peekaboo'' (ou ''Coucou cachée'') est un excellent exercice pour renforcer le lien avec votre chien, améliorer sa confiance en soi et travailler son rappel dans un environnement stimulant. Ce jeu consiste à se cacher et à réapparaître de manière ludique pour encourager votre chien à vous chercher et à venir vers vous. C''est une manière amusante d''introduire des notions de recherche et de récompense.', NULL, NULL, 'Peekaboo', 'Passer la tête entre les jambes par derrière', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien cherche activement son handler dès sa disparition et vient rapidement et avec enthousiasme vers lui lorsqu''il est invité, acceptant la récompense.', 'Le chien montre des signes de stress, de frustration excessive, ou un désintérêt total pour le jeu. Arrêter si le chien n''y arrive vraiment pas malgré plusieurs tentatives adaptées.', 'Observer si le chien cherche activement son handler lorsque celui-ci se cache et s''il vient à sa rencontre une fois qu''il apparaît. Noter la rapidité et l''enthousiasme de la réaction.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/peekaboo.png'),
('pen', 'Le ''Pen'' ou enclos est un exercice d''autocontrôle et de gestion de frustration. Il permet au chien d''apprendre à rester calme et contenu dans un espace délimité, même en présence de distractions. Cet exercice est idéal pour les chiens ayant tendance à l''hyperactivité ou à la réactivité.', NULL, NULL, 'Pen (enclos)', 'Enfermer le troupeau dans un enclos', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de rester calme dans l''enclos pendant 15 minutes avec des distractions modérées, sans montrer de signes de stress.', 'Le chien montre des signes de panique, de stress intense (halètement excessif, tremblements, salivation excessive) ou d''agressivité. Si le chien commence à comprendre l''exercice, mais qu''une session devient trop difficile, arrêtez-la avant qu''il ne soit trop frustré.', 'Le chien entre volontairement dans l''enclos, y reste calme et détendu sans aboyer ou gratter pendant la durée fixée, et sort sur commande.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pen.png'),
('personnes-handicapees', 'Cet exercice vise à désensibiliser votre chien à la présence et aux mouvements inhabituels des personnes à mobilité réduite, comme celles utilisant un fauteuil roulant ou des béquilles. L''objectif est d''assurer que votre chien reste calme, confiant et respectueux dans ces situations. Cela est crucial pour que votre chien puisse vous accompagner sereinement dans tous les environnements, y compris ceux où ces aides à la mobilité sont présentes.', NULL, NULL, 'Personnes à mobilité réduite', 'Accepter fauteuils roulants et béquilles', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien observe la personne à mobilité réduite sans manifester de stress, d''excitation excessive ou d''agressivité. Il reste concentré sur son propriétaire ou réagit calmement à la présence, sans tentatives de fuite ou d''interaction non désirée.', 'Le chien montre des signes clairs de stress, de peur (queue entre les pattes, halètement excessif, tremblements, tentative de fuite) ou une agressivité (grognements, grondements, tentatives de morsure). L''exercice doit être arrêté immédiatement si le bien-être du chien est compromis.', 'Observer le chien dans une situation réelle avec une personne à mobilité réduite, sans intervention du propriétaire, et noter sa réaction. Répéter plusieurs fois avec différentes personnes et contextes.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/personnes-handicapees.png'),
('personnes-agees', 'Cet exercice vise à habituer votre chien à la présence de personnes âgées, souvent caractérisées par des mouvements plus lents et une voix plus douce. L''objectif est de construire une association positive et de prévenir toute réaction de peur ou d''agression due à des différences perçues. Une bonne désensibilisation précoce permet d''assurer que votre chien interagisse calmement et respectueusement avec cette population.', NULL, NULL, 'Personnes âgées', 'Habituation aux mouvements lents/aides de marche', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et neutre en présence de personnes âgées variées et lors d''interactions douces et contrôlées. Il peut regarder la personne calmement, renifler une main tendue, ou ignorer la personne. Il ne manifeste plus de peur, d''aboiements, de grognements ou d''agressivité.', 'Le chien montre des signes clairs de stress, de peur (queue basse, léchage de babines excessif, halètement, tentatives de fuite) ou d''agressivité (grognements, tentative de mordiller). Si le chien est dépassé, il faut immédiatement arrêter la séance et s''éloigner.', 'Observer la réponse du chien à la présence de la personne âgée dans différentes positions (assis, debout, marchant lentement) et dans diverses distances. Le chien ne doit montrer aucun signe de peur, d''agression ou d''excitation excessive. Récompenser le comportement calme et l''absence de réaction négative.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/personnes-agees.png'),
('flair-patrouille', 'Le pistage de suspect est un exercice avancé d''éducation canine qui simule la recherche d''une personne disparue ou d''un suspect. Il développe le flair naturel du chien, sa concentration et son obéissance en situation. Cet exercice nécessite un environnement contrôlé et une gestion rigoureuse de la sécurité.', NULL, NULL, 'Pistage de suspect', 'Suivre la piste d''un individu en fuite', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien suit la piste de manière autonome avec une concentration soutenue, ignore les distractions et signale la présence du complice de manière calme et contrôlée.', 'Le chien montre des signes de stress excessif, de fatigue, de blessure, ou devient totalement désintéressé par l''exercice pendant une période prolongée après plusieurs tentatives.', 'Le chien doit être capable de suivre une piste d''odeur établie sur une distance et une durée définies, en passant par plusieurs changements de terrain, pour finalement localiser le complice et indiquer sa présence de manière claire.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/flair-patrouille.png'),
('pistage-urbain', 'Le pistage urbain est une activité stimulante qui apprend à votre chien à suivre une odeur spécifique dans un environnement complexe et plein de distractions. Il développe son flair, sa concentration et renforce votre complicité. C''est un excellent moyen d''occuper mentalement et physiquement votre chien.', NULL, NULL, 'Pistage urbain', 'Suivre une piste en milieu urbain', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de suivre une piste d''au moins 30 mètres en environnement urbain peu fréquenté, avec un seul virage, et de retrouver l''objet marqué en moins de 5 minutes.', 'Arrêter l''exercice si le chien montre des signes de frustration excessive, d''épuisement, ou si l''environnement devient dangereux (circulation soudaine, autres animaux agressifs).', 'Pour valider la recherche, le chien doit retrouver l''objet et le présenter au handler (en le rapportant ou en le signalant clairement par une attitude, comme un assis ou un couché près de l''objet).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pistage-urbain.png'),
('piste-avec-articles', 'La piste avec articles est un excellent exercice pour stimuler l''instinct de pistage de votre chien tout en renforçant votre complicité. Ce jeu consiste à cacher un objet que votre chien devra ensuite retrouver en suivant votre guidance. C''est une activité ludique adaptée à tous les chiens, indépendamment de leur race ou de leur âge.', NULL, NULL, 'Piste avec articles', 'Marquer les objets trouvés en cours de piste', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement en utilisant son flair, suit la piste laissée, retrouve l''objet et le rapporte ou le signale clairement. Il montre de l''enthousiasme et une bonne concentration pendant l''exercice.', 'Le chien montre une fatigue excessive, une frustration marquée (aboiements excessifs, recherche erratique), une perte d''intérêt totale pour l''objet, ou si des conditions extérieures (météo, environnement hostile) rendent l''exercice dangereux ou non productif.', 'La première validation est réussie lorsque le chien retrouve l''objet seul après un lancer court et simple, sur une piste droite. Augmentez la complexité (virages, objets multiples, distances variables) progressivement.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/piste-avec-articles.png'),
('piste-courte', 'La piste courte est un exercice d''olfaction ludique et stimulant pour votre chien. Il consiste à cacher un objet ou une friandise sur une courte distance et à demander à votre chien de le retrouver. Cet exercice renforce le lien entre vous et votre chien tout en satisfaisant son besoin naturel de flairer.', NULL, NULL, 'Piste courte (5m)', 'Suivre une piste de 5 mètres', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien trouve l''objet en moins de 2 minutes, en suivant fidèlement la piste (même avec un virage subtil) et en montrant une bonne motivation pour la recherche. Le handler n''a pas eu besoin de donner d''indices majeurs.', 'Le chien montre une perte d''intérêt marquée, est excessivement distrait et ne répond plus aux commandes. Le chien est fatigué ou stressé. L''exercice devient une source de frustration pour le chien ou le handler.', 'Le chien doit pouvoir retrouver l''objet caché sur une piste de 5 mètres dans un environnement faiblement distrayant, en parcourant la quasi-totalité de la piste. L''objectif est qu''il utilise activement son flair.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/piste-courte.png'),
('piste-en-foret', 'La piste en forêt est un jeu de flair qui stimule mentalement et physiquement votre chien. Il s''agit de suivre une odeur laissée sur le parcours, développant ainsi son instinct naturel de pisteur. Cet exercice renforce votre complicité et est idéal pour dépenser l''énergie de votre chien dans un environnement riche en distractions.', NULL, NULL, 'Piste en forêt', 'Pistage en milieu boisé complexe', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien suit la piste de manière autonome sur une distance raisonnable (adaptée à son niveau) en utilisant son flair, et se montre satisfait à la fin. Il ne se laisse pas distraire facilement par les odeurs environnantes.', 'Le chien montre des signes de fatigue, de frustration ou désintérêt marqués. L''environnement devient trop dangereux ou trop stressant pour le chien. La séance dure trop longtemps sans pause.', 'Une fois que le chien suit la piste sans aide, vous pouvez vérifier qu''il apprécie l''activité et qu''il est engageant. Le chien doit rechercher activement les friandises ou l''objet.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/piste-en-foret.png'),
('piste-longue', 'La piste longue est un exercice olfactif avancé qui sollicite le nez et le cerveau de votre chien. Il s''agit de lui faire suivre une piste de senteur traçable sur une distance considérable, souvent dans des environnements variés. Cet exercice renforce la concentration, la persévérance et la confiance en soi de votre chien tout en lui offrant une dépense mentale et physique très satisfaisante.', NULL, NULL, 'Piste longue (50m+)', 'Suivre une longue piste avec virages', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien suit la piste sur la distance définie, démontre une concentration soutenue et trouve l''objet de récompense à la fin de manière autonome. Il ne s''arrête pas ou ne dévie pas significativement de la piste.', 'Le chien montre des signes de stress, de frustration ou de fatigue excessive. Il refuse catégoriquement de chercher ou devient agressif. Le handler ne parvient pas à maintenir la sécurité ou le bien-être du chien.', 'Observez la capacité du chien à suivre la piste de manière autonome sur la distance demandée, sans distractions majeures, et à trouver l''objet final. Vérifiez la concentration du chien et sa persévérance.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/piste-longue.png'),
('piste-moyenne', 'Cet exercice vise à développer le flair de votre chien sur une piste de longueur moyenne. Il apprendra à suivre des odeurs spécifiques laissées sur le sol, le guidant vers une récompense cachée. C''est une excellente activité pour stimuler mentalement et physiquement votre compagnon canin.', NULL, NULL, 'Piste moyenne (20m)', 'Suivre une piste de 20 mètres', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien suit fidèlement la piste sans distraction excessive et retrouve l''objet à la fin dans un délai raisonnable (variable selon le chien et la difficulté).', 'Arrêter si le chien montre des signes de stress, de frustration ou de fatigue excessive, ou s''il refuse catégoriquement de participer à l''exercice malgré plusieurs tentatives.', 'Chaque fois que le chien suit la piste et retrouve l''objet de manière autonome ou avec un guidage minimal, l''exercice est considéré comme réussi pour cette tentative.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/piste-moyenne.png'),
('piste-vieille', 'La piste vieillie sur 2 heures ou plus est un exercice avancé qui mettra à l''épreuve l''endurance et le flair de votre chien. Il consiste à suivre une piste rendue difficile par le temps et les éléments. Cet exercice est idéal pour les chiens ayant déjà une bonne expérience en pistage et qui recherchent un défi olfactif plus intense.', NULL, NULL, 'Piste vieillie (2h+)', 'Suivre une piste posée il y a 2 heures', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien retrouve l''objet en suivant la piste avec persévérance, sans interruption majeure. La recherche doit être autonome et concentrée.', 'Le chien se détourne complètement de la piste, devient totalement désintéressé, montre des signes de stress ou de fatigue extrêmes, ou s''il ne trouve absolument pas la piste après un temps raisonnable et plusieurs tentatives assistées.', 'Observer si le chien arrive à retrouver l''objet caché. Vérifier la qualité de sa recherche : nez au sol, progression constante, intérêt marqué pour la piste.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/piste-vieille.png'),
('pivot-arriere', 'Le pivot arrière est un exercice fondamental pour apprendre au chien à se déplacer en cercle autour de sa propre patte arrière. Cet exercice améliore la proprioception, la coordination et la confiance du chien. Il est essentiel pour des exercices plus complexes comme le ''tourne'' et le ''cerca''.', NULL, NULL, 'Pivot arrière', 'Les pattes arrière tournent autour d''un objet', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien pivote de manière fluide et coordonnée en cercle autour de sa patte arrière sur une commande vocale, sans hésitation ni guidage excessif de la main. Il devrait être capable de faire plusieurs pivots consécutifs.', 'Le chien montre des signes de fatigue, de frustration ou de stress. Il refuse de participer à l''exercice ou commence à montrer des comportements indésirables comme mâchouiller la laisse ou s''éloigner.', 'Pour valider que le chien comprend le mouvement, il doit être capable de faire un pivot complet de 360 degrés en suivant le guidage de la main, puis répondre à une commande vocale pour faire le pivot.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pivot-arriere.png'),
('planche-wobble', 'La planche d''équilibre est un excellent exercice pour développer la proprioception, la confiance en soi et la musculature de votre chien. Elle se travaille progressivement, en commençant par de courtes sessions et en augmentant la durée à mesure que votre chien gagne en aisance. Cet exercice est bénéfique pour tous les chiens, qu''ils soient jeunes, âgés, sportifs ou souffrant de problèmes de mobilité.', NULL, NULL, 'Planche d''équilibre', 'Se tenir sur une planche instable', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte volontairement sur la planche, reste calme et confortable pendant la durée de l''exercice, et exécute les commandes demandées avec une légère inclinaison de la planche.', 'Le chien montre des signes de stress importants (bâillements excessifs, léchage des babines, évitement, tremblements), une douleur articulaire ou musculaire évidente, ou une lassitude marquée. Interrompre l''exercice si le chien se blesse.', 'Observer la réaction du chien (curiosité, peur, confiance) à la présence de la planche et à son utilisation. Noter les réactions aux commandes verbales et aux mouvements de la planche.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/planche-wobble.png'),
('porte-fermee', 'Le ''Porte fermée progressif'' est un exercice qui apprend au chien à rester calme et détendu lorsque la porte se ferme devant lui. Il aide à prévenir l''anxiété de séparation ou la frustration liée aux portes. Cet exercice renforce la confiance du chien et sa capacité à gérer les séparations temporaires.', NULL, NULL, 'Porte fermée progressif', 'Fermer la porte progressivement', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme pendant que la porte se ferme devant lui, ne montre aucune réaction de stress, et attend calmement l''instruction de passer ou de rester.', 'Le chien montre de l''anxiété, de la peur, de la frustration, ou une excitation excessive. L''exercice devient une source de stress pour le chien.', 'Observer la réaction du chien à la fermeture de la porte à chaque étape. Le chien doit rester calme, sans signes de stress (halètement excessif, salivation, tremblements, griffements, aboiements).', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/porte-fermee.png'),
('porter-panier', 'L''exercice "Porter un panier" apprend à votre chien à saisir et à transporter un objet désigné, comme un panier. C''est un excellent exercice pour renforcer le lien, stimuler mentalement votre chien et développer sa confiance. Cet exercice peut être adapté pour différents types d''objets et de tailles de paniers.', NULL, NULL, 'Porter un panier', 'Transporter un panier en gueule', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien saisit le panier volontairement, le transporte sur une courte distance (environ 2 mètres) et le lâche sur demande, avec un comportement général positif et confiant.', 'Le chien montre des signes de stress, de fatigue excessive, ou d''agressivité envers l''objet ou le handler. Si le chien persévère dans l''échec malgré les adaptations.', 'Observer la capacité du chien à saisir activement le panier avec sa gueule, le maintenir pendant au moins 3 secondes, puis le relâcher sur commande.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/porter-panier.png'),
('positions-ring', 'Cet exercice enseigne au chien à maintenir une position assise ou couchée à distance, en répondant aux commandes verbales ou gestuelles. Il améliore la concentration, le contrôle de soi et la confiance du chien dans différentes situations. C''est une base essentielle pour des comportements avancés et une communication claire entre le propriétaire et le chien.', NULL, NULL, 'Positions à distance (ring)', 'Assis-couché-debout à 15m+', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste impeccablement en position à 10 mètres, sans bouger, pendant 30 secondes, même avec des distractions modérées (ex: une balle lancée à proximité, une autre personne passant). Le chien ne rompt la position que sur commande.', 'Le chien rompt la position de manière répétée malgré les ajustements de distance, de durée ou de distraction. Le chien montre des signes de stress, de frustration ou de peur. L''exercice n''est plus amusant ou productif pour le chien ou le handler.', 'Après avoir effectué les étapes du tutoriel, le chien doit maintenir sa position assise ou couchée à une distance de 10 mètres du handler pendant au moins 30 secondes, sans distraction. Le handler doit pouvoir tourner le dos au chien et revenir le chercher.', 'Observer le langage corporel', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/positions-ring.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;